-- ============================================================================
-- Quiz Seed: Gospel of John (Chapters 1–21)
-- 3 difficulties × 21 chapters = 336 total questions
--   kids:   3 per chapter  =  63
--   teens:  5 per chapter  = 105
--   adults: 8 per chapter  = 168
-- ============================================================================

-- ═══════════════════════════════════════════════════════════════════════════
-- CHAPTERS 1 – 5
-- ═══════════════════════════════════════════════════════════════════════════

-- ═══ John Chapter 1 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('John', 1, 'kids', 1, 'What was "in the beginning" according to John chapter 1?', 'The Word', 'The Temple', 'The Law', 'The Sea', 'a', 'John 1:1 says "In the beginning was the Word."'),
('John', 1, 'kids', 2, 'What did John the Baptist call Jesus when he saw Him?', 'The Lamb of God', 'The King of Israel', 'The Son of David', 'The Great Teacher', 'a', 'John 1:29 says "Behold the Lamb of God, which taketh away the sin of the world."'),
('John', 1, 'kids', 3, 'Which disciple did Andrew bring to Jesus?', 'Simon Peter', 'James', 'John', 'Thomas', 'a', 'John 1:41-42 tells us Andrew brought his brother Simon Peter to Jesus.'),
-- Teens
('John', 1, 'teens', 1, 'According to John 1:1, what is the relationship between the Word and God?', 'The Word was God', 'The Word was an angel', 'The Word was created by God', 'The Word served God', 'a', 'John 1:1 states "the Word was with God, and the Word was God."'),
('John', 1, 'teens', 2, 'What role did John the Baptist say he played?', 'The voice of one crying in the wilderness', 'The prophet foretold by Moses', 'The messenger of the temple', 'The shepherd of Israel', 'a', 'John 1:23 — John said "I am the voice of one crying in the wilderness."'),
('John', 1, 'teens', 3, 'What new name did Jesus give to Simon?', 'Cephas (Peter)', 'Barnabas', 'Israel', 'Boanerges', 'a', 'John 1:42 says Jesus called him "Cephas, which is by interpretation, A stone."'),
('John', 1, 'teens', 4, 'What convinced Nathanael that Jesus was the Son of God?', 'Jesus saw him under the fig tree before Philip called him', 'Jesus healed his sickness', 'Jesus quoted Scripture to him', 'Jesus turned water into wine', 'a', 'John 1:48-49 — Jesus saw Nathanael under the fig tree, and Nathanael believed.'),
('John', 1, 'teens', 5, 'What did Jesus promise Nathanael he would see?', 'Heaven open and angels ascending and descending upon the Son of man', 'The temple destroyed and rebuilt', 'The dead raised to life', 'Fire coming down from heaven', 'a', 'John 1:51 — "Ye shall see heaven open, and the angels of God ascending and descending upon the Son of man."'),
-- Adults
('John', 1, 'adults', 1, 'In John 1:3, what does the text say was made without the Word?', 'Not any thing that was made', 'Only heavenly things', 'Only living creatures', 'Only mankind', 'a', 'John 1:3 says "without him was not any thing made that was made."'),
('John', 1, 'adults', 2, 'What specific title does John 1:18 use for Jesus in relation to the Father?', 'The only begotten Son, which is in the bosom of the Father', 'The firstborn of all creation', 'The beloved Son in whom I am well pleased', 'The express image of His person', 'a', 'John 1:18 — "the only begotten Son, which is in the bosom of the Father, he hath declared him."'),
('John', 1, 'adults', 3, 'According to John 1:12-13, those who received Jesus were born of what?', 'God — not of blood, nor of the will of the flesh, nor of the will of man', 'Water and the Spirit', 'The word of truth', 'Incorruptible seed', 'a', 'John 1:13 — "born, not of blood, nor of the will of the flesh, nor of the will of man, but of God."'),
('John', 1, 'adults', 4, 'What did John the Baptist explicitly deny being when questioned by the priests and Levites?', 'The Christ, Elijah, and "that prophet"', 'A Pharisee, a Sadducee, and a scribe', 'Moses, Elijah, and David', 'A priest, a king, and a prophet', 'a', 'John 1:20-21 — He denied being the Christ, Elijah, or "that prophet."'),
('John', 1, 'adults', 5, 'Where was John baptizing when he identified Jesus as the Lamb of God?', 'Bethabara beyond Jordan', 'The Jordan near Jericho', 'The Sea of Galilee', 'The pool of Siloam', 'a', 'John 1:28 — "These things were done in Bethabara beyond Jordan, where John was baptizing."'),
('John', 1, 'adults', 6, 'What sign did God give John the Baptist to identify the Messiah?', 'The one upon whom the Spirit descends and remains', 'A voice from heaven', 'A star appearing in the east', 'Fire falling from the sky', 'a', 'John 1:33 — "Upon whom thou shalt see the Spirit descending, and remaining on him, the same is he."'),
('John', 1, 'adults', 7, 'What was the approximate hour when the two disciples of John first stayed with Jesus?', 'The tenth hour (about 4 PM)', 'The sixth hour (about noon)', 'The third hour (about 9 AM)', 'The ninth hour (about 3 PM)', 'a', 'John 1:39 — "It was about the tenth hour."'),
('John', 1, 'adults', 8, 'What did Philip tell Nathanael about where Jesus was from, and what was Nathanael''s response?', 'Nazareth; "Can there any good thing come out of Nazareth?"', 'Bethlehem; "Is not this the city of David?"', 'Capernaum; "That is far from the temple."', 'Jerusalem; "Surely the Messiah comes from Judah."', 'a', 'John 1:46 — Nathanael said "Can there any good thing come out of Nazareth?"'),

-- ═══ John Chapter 2 ═══
-- Kids
('John', 2, 'kids', 1, 'What did Jesus turn into wine at the wedding?', 'Water', 'Milk', 'Juice', 'Oil', 'a', 'John 2:9 tells us Jesus turned water into wine at the wedding in Cana.'),
('John', 2, 'kids', 2, 'Where was the wedding that Jesus attended?', 'Cana in Galilee', 'Jerusalem', 'Bethlehem', 'Nazareth', 'a', 'John 2:1 says "there was a marriage in Cana of Galilee."'),
('John', 2, 'kids', 3, 'What did Jesus do in the temple that upset the merchants?', 'He drove them out with a whip and overturned their tables', 'He closed the doors on them', 'He refused to buy their animals', 'He told the priests to fire them', 'a', 'John 2:15 — Jesus made a scourge and drove them out and overthrew the tables.'),
-- Teens
('John', 2, 'teens', 1, 'Who told Jesus that the wedding had run out of wine?', 'His mother Mary', 'His disciple John', 'The governor of the feast', 'The bridegroom', 'a', 'John 2:3 — "the mother of Jesus saith unto him, They have no wine."'),
('John', 2, 'teens', 2, 'How many waterpots of stone were there, and how much did each hold?', 'Six waterpots, holding two or three firkins each', 'Four waterpots, holding one firkin each', 'Ten waterpots, holding five firkins each', 'Two waterpots, holding ten firkins each', 'a', 'John 2:6 — "six waterpots of stone… containing two or three firkins apiece."'),
('John', 2, 'teens', 3, 'What did the governor of the feast say about when good wine is usually served?', 'At the beginning of the feast, not at the end', 'At the end of the feast as a surprise', 'Only to the most important guests', 'Only after the meal is finished', 'a', 'John 2:10 — "Every man at the beginning doth set forth good wine… thou hast kept the good wine until now."'),
('John', 2, 'teens', 4, 'When Jesus said "Destroy this temple, and in three days I will raise it up," what temple did He mean?', 'His own body', 'Herod''s temple in Jerusalem', 'A new heavenly temple', 'Solomon''s original temple', 'a', 'John 2:21 — "he spake of the temple of his body."'),
('John', 2, 'teens', 5, 'What was this miracle at Cana described as in the Gospel of John?', 'The beginning of miracles (signs)', 'The greatest miracle of all', 'A secret miracle known only to the disciples', 'The seventh sign', 'a', 'John 2:11 — "This beginning of miracles did Jesus in Cana of Galilee."'),
-- Adults
('John', 2, 'adults', 1, 'What exact words did Jesus speak to Mary when she mentioned the wine shortage?', '"Woman, what have I to do with thee? mine hour is not yet come"', '"Mother, it is not yet my time to act"', '"Why do you trouble me with this matter?"', '"Be patient, for the Father''s will must be done"', 'a', 'John 2:4 — "Woman, what have I to do with thee? mine hour is not yet come."'),
('John', 2, 'adults', 2, 'What did Mary instruct the servants to do after Jesus'' response?', '"Whatsoever he saith unto you, do it"', '"Bring more water from the well"', '"Wait for his command"', '"Fill the pots with new wine"', 'a', 'John 2:5 — "His mother saith unto the servants, Whatsoever he saith unto you, do it."'),
('John', 2, 'adults', 3, 'What items did Jesus use to drive out the merchants from the temple?', 'A scourge of small cords', 'A rod of iron', 'A staff of wood', 'His bare hands only', 'a', 'John 2:15 — "when he had made a scourge of small cords, he drove them all out."'),
('John', 2, 'adults', 4, 'What Old Testament passage did the disciples remember when Jesus cleansed the temple?', '"The zeal of thine house hath eaten me up" (Psalm 69:9)', '"My house shall be called a house of prayer" (Isaiah 56:7)', '"The Lord whom ye seek shall suddenly come to his temple" (Malachi 3:1)', '"Holiness becometh thine house" (Psalm 93:5)', 'a', 'John 2:17 — "His disciples remembered that it was written, The zeal of thine house hath eaten me up."'),
('John', 2, 'adults', 5, 'How long did the Jews say the temple had been under construction?', 'Forty and six years', 'Thirty years', 'Twenty years', 'Seventy years', 'a', 'John 2:20 — "Forty and six years was this temple in building."'),
('John', 2, 'adults', 6, 'Why did Jesus not commit Himself to those who believed during the Passover feast?', 'Because He knew all men and what was in man', 'Because they were Pharisees in disguise', 'Because they only wanted earthly bread', 'Because the time had not yet come', 'a', 'John 2:24-25 — "Jesus did not commit himself unto them, because he knew all men."'),
('John', 2, 'adults', 7, 'What theological significance does John attach to the water-to-wine miracle?', 'It manifested His glory and His disciples believed on Him', 'It proved He was greater than Moses', 'It fulfilled the prophecy of the Messianic banquet', 'It showed His authority over nature', 'a', 'John 2:11 — "manifested forth his glory; and his disciples believed on him."'),
('John', 2, 'adults', 8, 'After the wedding at Cana, where did Jesus go with His family and disciples?', 'Capernaum, where they stayed not many days', 'Jerusalem for the Passover', 'Nazareth to His hometown', 'Bethany beyond Jordan', 'a', 'John 2:12 — "he went down to Capernaum… and they continued there not many days."'),

-- ═══ John Chapter 3 ═══
-- Kids
('John', 3, 'kids', 1, 'Who came to talk to Jesus at night?', 'Nicodemus', 'Peter', 'John the Baptist', 'Pilate', 'a', 'John 3:1-2 — Nicodemus came to Jesus by night.'),
('John', 3, 'kids', 2, 'What did Jesus say a person must be to see the kingdom of God?', 'Born again', 'Very rich', 'Very strong', 'Very old', 'a', 'John 3:3 — "Except a man be born again, he cannot see the kingdom of God."'),
('John', 3, 'kids', 3, 'In John 3:16, what did God give because He loved the world?', 'His only begotten Son', 'A new set of laws', 'The land of Israel', 'The Ten Commandments', 'a', 'John 3:16 — "God so loved the world, that he gave his only begotten Son."'),
-- Teens
('John', 3, 'teens', 1, 'What group did Nicodemus belong to?', 'The Pharisees and rulers of the Jews', 'The Sadducees', 'The Essenes', 'The Zealots', 'a', 'John 3:1 — "a man of the Pharisees, named Nicodemus, a ruler of the Jews."'),
('John', 3, 'teens', 2, 'What two things did Jesus say a man must be born of to enter the kingdom of God?', 'Water and the Spirit', 'Fire and the Spirit', 'Blood and water', 'The Word and faith', 'a', 'John 3:5 — "Except a man be born of water and of the Spirit, he cannot enter into the kingdom of God."'),
('John', 3, 'teens', 3, 'What Old Testament event did Jesus compare to His being "lifted up"?', 'Moses lifting up the serpent in the wilderness', 'Elijah being taken up in a chariot of fire', 'The ark being lifted above the flood waters', 'Abraham offering Isaac on the mountain', 'a', 'John 3:14 — "as Moses lifted up the serpent in the wilderness, even so must the Son of man be lifted up."'),
('John', 3, 'teens', 4, 'According to John 3:16, what happens to whoever believes in God''s Son?', 'They shall not perish but have everlasting life', 'They shall be healed of all diseases', 'They shall become rulers of the earth', 'They shall never face any trials', 'a', 'John 3:16 — "whosoever believeth in him should not perish, but have everlasting life."'),
('John', 3, 'teens', 5, 'What did John the Baptist say must happen regarding himself and Jesus?', '"He must increase, but I must decrease"', '"We must serve together as equals"', '"I must prepare His throne"', '"He must teach and I must baptize"', 'a', 'John 3:30 — "He must increase, but I must decrease."'),
-- Adults
('John', 3, 'adults', 1, 'What title did Nicodemus use for Jesus, and what reason did he give?', 'Rabbi — "no man can do these miracles that thou doest, except God be with him"', 'Lord — "thou art the Christ, the Son of the living God"', 'Prophet — "we have heard of thy fame in all the land"', 'Master — "thy words are spirit and life"', 'a', 'John 3:2 — "Rabbi, we know that thou art a teacher come from God: for no man can do these miracles… except God be with him."'),
('John', 3, 'adults', 2, 'What rebuke did Jesus give Nicodemus regarding his understanding?', '"Art thou a master of Israel, and knowest not these things?"', '"You have studied the law but missed its meaning"', '"How can you teach others when you have not been taught?"', '"Even the common people understand what you cannot"', 'a', 'John 3:10 — "Art thou a master of Israel, and knowest not these things?"'),
('John', 3, 'adults', 3, 'In John 3:13, who does Jesus say has ascended to heaven?', 'No man — only the Son of man which came down from heaven', 'Elijah who was taken up in a whirlwind', 'Moses who spoke with God on the mountain', 'Enoch who walked with God', 'a', 'John 3:13 — "no man hath ascended up to heaven, but he that came down from heaven, even the Son of man."'),
('John', 3, 'adults', 4, 'According to John 3:17-18, why was the Son sent into the world?', 'Not to condemn the world, but that the world through Him might be saved', 'To judge between the righteous and the wicked', 'To establish the kingdom of God on earth', 'To destroy the works of the devil', 'a', 'John 3:17 — "God sent not his Son into the world to condemn the world; but that the world through him might be saved."'),
('John', 3, 'adults', 5, 'What does John 3:19 identify as the condemnation of mankind?', 'Light came into the world, and men loved darkness rather than light', 'Men rejected the prophets sent to them', 'Men worshipped idols instead of the true God', 'Men trusted in their own works', 'a', 'John 3:19 — "this is the condemnation, that light is come into the world, and men loved darkness rather than light."'),
('John', 3, 'adults', 6, 'What dispute arose between John the Baptist''s disciples and the Jews?', 'A question about purifying (ceremonial washing)', 'A debate about the coming Messiah', 'A disagreement about Sabbath observance', 'A conflict about temple sacrifices', 'a', 'John 3:25 — "there arose a question between some of John''s disciples and the Jews about purifying."'),
('John', 3, 'adults', 7, 'What analogy does Jesus use for the work of the Spirit in regeneration?', 'The wind blows where it wishes — you hear the sound but cannot tell where it comes from or goes', 'Water flowing from a spring into a river', 'Fire consuming dry wood', 'A seed growing secretly in the earth', 'a', 'John 3:8 — "The wind bloweth where it listeth, and thou hearest the sound thereof, but canst not tell whence it cometh."'),
('John', 3, 'adults', 8, 'What does John 3:36 say about the person who does not believe the Son?', 'He shall not see life, and the wrath of God abideth on him', 'He will be given another chance at judgment', 'He will simply cease to exist', 'He will be sent to a place of waiting', 'a', 'John 3:36 — "he that believeth not the Son shall not see life; but the wrath of God abideth on him."'),

-- ═══ John Chapter 4 ═══
-- Kids
('John', 4, 'kids', 1, 'Where did Jesus meet a woman and ask her for a drink of water?', 'At a well in Samaria', 'At the Sea of Galilee', 'At the temple in Jerusalem', 'At a river near Bethlehem', 'a', 'John 4:6-7 — Jesus sat on Jacob''s well in Samaria and asked the woman for a drink.'),
('John', 4, 'kids', 2, 'What special kind of water did Jesus offer the woman?', 'Living water', 'Holy water', 'River water', 'Rain water', 'a', 'John 4:10 — Jesus said He would give her "living water."'),
('John', 4, 'kids', 3, 'What happened to the nobleman''s son after Jesus spoke a word?', 'He was healed', 'He fell asleep', 'He ran away', 'He began to cry', 'a', 'John 4:50-53 — Jesus said "Thy son liveth" and the boy was healed.'),
-- Teens
('John', 4, 'teens', 1, 'Why was the Samaritan woman surprised that Jesus spoke to her?', 'Jews had no dealings with Samaritans', 'Women were not allowed to speak to strangers', 'She was a known sinner in the town', 'He was a rabbi and she was uneducated', 'a', 'John 4:9 — "the Jews have no dealings with the Samaritans."'),
('John', 4, 'teens', 2, 'How many husbands had the woman at the well had?', 'Five, and the man she was with was not her husband', 'Three, and she was a widow', 'Seven, and she had been divorced by each', 'Two, and she was looking for a third', 'a', 'John 4:18 — "thou hast had five husbands; and he whom thou now hast is not thy husband."'),
('John', 4, 'teens', 3, 'What did Jesus say about how true worshippers must worship God?', 'In spirit and in truth', 'In the temple at Jerusalem only', 'With sacrifices and offerings', 'On the mountain in Samaria', 'a', 'John 4:23-24 — "true worshippers shall worship the Father in spirit and in truth."'),
('John', 4, 'teens', 4, 'What did the Samaritan woman do after speaking with Jesus?', 'She left her waterpot and told the men of the city about Jesus', 'She brought her husband to meet Jesus', 'She began to weep and ask for forgiveness', 'She invited Jesus to her home for dinner', 'a', 'John 4:28-29 — She left her waterpot and said "Come, see a man, which told me all things that ever I did."'),
('John', 4, 'teens', 5, 'How long did the Samaritans ask Jesus to stay with them?', 'Two days', 'Seven days', 'One day', 'A full week', 'a', 'John 4:40 — "they besought him that he would tarry with them: and he abode there two days."'),
-- Adults
('John', 4, 'adults', 1, 'Whose well was the Samaritan woman drawing from, according to the text?', 'Jacob''s well, near the parcel of ground Jacob gave to Joseph', 'Abraham''s well at Beer-sheba', 'Moses'' well in the wilderness', 'Isaac''s well at Gerar', 'a', 'John 4:5-6 — "Jacob''s well was there." The land was near what "Jacob gave to his son Joseph."'),
('John', 4, 'adults', 2, 'What hour was it when Jesus sat on the well?', 'About the sixth hour (noon)', 'About the third hour (9 AM)', 'About the ninth hour (3 PM)', 'About the tenth hour (4 PM)', 'a', 'John 4:6 — "it was about the sixth hour."'),
('John', 4, 'adults', 3, 'What did Jesus describe as His "meat" (food)?', 'To do the will of Him that sent Him and to finish His work', 'The bread of life that comes from heaven', 'The Word of God alone', 'Prayer and fasting before the Father', 'a', 'John 4:34 — "My meat is to do the will of him that sent me, and to finish his work."'),
('John', 4, 'adults', 4, 'What agricultural metaphor did Jesus use about the harvest in Samaria?', '"Lift up your eyes and look on the fields; for they are white already to harvest"', '"The sower and the reaper shall rejoice together at the end"', '"The wheat and the tares grow together until the harvest"', '"First the blade, then the ear, then the full corn"', 'a', 'John 4:35 — "Lift up your eyes, and look on the fields; for they are white already to harvest."'),
('John', 4, 'adults', 5, 'What did the Samaritans ultimately confess about Jesus after His two-day stay?', '"This is indeed the Christ, the Saviour of the world"', '"This man is truly a great prophet"', '"He is the one Moses wrote about"', '"He is the Son of David who was promised"', 'a', 'John 4:42 — "this is indeed the Christ, the Saviour of the world."'),
('John', 4, 'adults', 6, 'Where was the nobleman from, and where was his sick son?', 'The nobleman was in Cana; his son was in Capernaum', 'The nobleman was in Jerusalem; his son was in Bethany', 'The nobleman was in Nazareth; his son was in Cana', 'The nobleman was in Bethsaida; his son was in Tiberias', 'a', 'John 4:46-47 — Jesus was in Cana; the nobleman came to Him, and his son was sick in Capernaum.'),
('John', 4, 'adults', 7, 'What did Jesus say to the nobleman that initially seemed like a rebuke?', '"Except ye see signs and wonders, ye will not believe"', '"O ye of little faith, why do you doubt?"', '"Your sins have caused this illness"', '"Go first and offer sacrifice in the temple"', 'a', 'John 4:48 — "Except ye see signs and wonders, ye will not believe."'),
('John', 4, 'adults', 8, 'What number sign/miracle in John''s Gospel was the healing of the nobleman''s son?', 'The second miracle that Jesus did in Cana of Galilee', 'The third sign performed in Judea', 'The first miracle after leaving Jerusalem', 'The fourth sign of His ministry', 'a', 'John 4:54 — "This is again the second miracle that Jesus did, when he was come out of Judaea into Galilee."'),

-- ═══ John Chapter 5 ═══
-- Kids
('John', 5, 'kids', 1, 'How long had the man at the pool been sick?', 'Thirty-eight years', 'Twelve years', 'Seven years', 'Three years', 'a', 'John 5:5 — "a certain man was there, which had an infirmity thirty and eight years."'),
('John', 5, 'kids', 2, 'What did Jesus tell the sick man to do?', '"Rise, take up thy bed, and walk"', '"Go wash in the pool"', '"Call your friends to help you"', '"Wait for an angel to come"', 'a', 'John 5:8 — "Jesus saith unto him, Rise, take up thy bed, and walk."'),
('John', 5, 'kids', 3, 'What day of the week did Jesus heal the man at the pool?', 'The Sabbath', 'The first day of the week', 'A feast day', 'The day before Passover', 'a', 'John 5:9 — "and on the same day was the sabbath."'),
-- Teens
('John', 5, 'teens', 1, 'What was the name of the pool where Jesus healed the man?', 'Bethesda', 'Siloam', 'Bethany', 'Solomon', 'a', 'John 5:2 — "a pool, which is called in the Hebrew tongue Bethesda."'),
('John', 5, 'teens', 2, 'Why were the Jewish leaders upset with the healed man?', 'He was carrying his bed on the Sabbath', 'He was shouting in the temple', 'He did not thank the priests first', 'He told everyone about the healing', 'a', 'John 5:10 — "The Jews therefore said unto him that was cured, It is the sabbath day: it is not lawful for thee to carry thy bed."'),
('John', 5, 'teens', 3, 'What did Jesus warn the healed man about when He found him in the temple?', '"Sin no more, lest a worse thing come unto thee"', '"Go and show thyself to the priest"', '"Tell no man about this healing"', '"Leave Jerusalem before the feast"', 'a', 'John 5:14 — "sin no more, lest a worse thing come unto thee."'),
('John', 5, 'teens', 4, 'Why did the Jews seek to kill Jesus after this healing?', 'He healed on the Sabbath and said God was His Father, making Himself equal with God', 'He claimed to be greater than Moses', 'He refused to obey the temple authorities', 'He told the man not to follow Jewish law', 'a', 'John 5:18 — "he had broken the sabbath, and said also that God was his Father, making himself equal with God."'),
('John', 5, 'teens', 5, 'According to Jesus, who will hear the voice of the Son of God and live?', 'The dead — and the hour is coming and now is', 'Only the righteous who keep the law', 'Only those who are baptized', 'Only the priests in the temple', 'a', 'John 5:25 — "The hour is coming, and now is, when the dead shall hear the voice of the Son of God: and they that hear shall live."'),
-- Adults
('John', 5, 'adults', 1, 'How many porches surrounded the pool of Bethesda?', 'Five', 'Three', 'Four', 'Seven', 'a', 'John 5:2 — "a pool, which is called in the Hebrew tongue Bethesda, having five porches."'),
('John', 5, 'adults', 2, 'What did Jesus claim about His relationship to the Father''s ongoing work?', '"My Father worketh hitherto, and I work"', '"I do only what the prophets commanded"', '"The Father rests, but I continue His plan"', '"I work by the power of the Spirit alone"', 'a', 'John 5:17 — "My Father worketh hitherto, and I work."'),
('John', 5, 'adults', 3, 'According to John 5:22, what has the Father committed entirely to the Son?', 'All judgment', 'All creation', 'All prophecy', 'All healing', 'a', 'John 5:22 — "the Father judgeth no man, but hath committed all judgment unto the Son."'),
('John', 5, 'adults', 4, 'What four witnesses to Jesus does He enumerate in chapter 5?', 'John the Baptist, His works, the Father, and the Scriptures', 'Moses, Elijah, the prophets, and the angels', 'Peter, James, John, and Andrew', 'The miracles, the temple, the law, and the sacrifices', 'a', 'John 5:33-39 — John''s testimony (v33), Jesus'' works (v36), the Father (v37), and the Scriptures (v39).'),
('John', 5, 'adults', 5, 'What did Jesus say the Jews searched the Scriptures for, thinking they had it in them?', 'Eternal life — and "they are they which testify of me"', 'The secrets of God''s kingdom', 'The exact date of the Messiah''s coming', 'Wisdom and understanding of the law', 'a', 'John 5:39 — "Search the scriptures; for in them ye think ye have eternal life: and they are they which testify of me."'),
('John', 5, 'adults', 6, 'Whom did Jesus say would accuse the Jews to the Father?', 'Moses, in whom they trusted', 'Elijah the prophet', 'John the Baptist', 'The angels of God', 'a', 'John 5:45 — "there is one that accuseth you, even Moses, in whom ye trust."'),
('John', 5, 'adults', 7, 'What two types of resurrection does Jesus describe in John 5:29?', 'The resurrection of life and the resurrection of damnation', 'The resurrection of the body and the resurrection of the spirit', 'The first resurrection and the final resurrection', 'The resurrection of the righteous and the sleep of the wicked', 'a', 'John 5:29 — "they that have done good, unto the resurrection of life; and they that have done evil, unto the resurrection of damnation."'),
('John', 5, 'adults', 8, 'What reason did Jesus give for why the Jews could not believe in Him?', 'They received honour from one another and did not seek the honour that comes from God only', 'They were blinded by Satan''s deceptions', 'They had never read the Scriptures properly', 'They were afraid of losing their positions of power', 'a', 'John 5:44 — "How can ye believe, which receive honour one of another, and seek not the honour that cometh from God only?"');

