-- CHAPTERS 6 – 10
-- ═══════════════════════════════════════════════════════════════════════════

-- ═══ John Chapter 6 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('John', 6, 'kids', 1, 'How many people did Jesus feed with a boy''s lunch?', 'About five thousand', 'About one hundred', 'About one thousand', 'About ten thousand', 'a', 'John 6:10 — "the men sat down, in number about five thousand."'),
('John', 6, 'kids', 2, 'What food did the boy have that Jesus used to feed the crowd?', 'Five barley loaves and two small fishes', 'Seven loaves and a few fishes', 'Three loaves and five fishes', 'Ten loaves and one fish', 'a', 'John 6:9 — "five barley loaves, and two small fishes."'),
('John', 6, 'kids', 3, 'What amazing thing did Jesus do on the sea that night?', 'He walked on the water', 'He calmed a great storm', 'He caught many fish', 'He made the boat fly', 'a', 'John 6:19 — "they see Jesus walking on the sea."'),
-- Teens
('John', 6, 'teens', 1, 'How many baskets of leftovers were collected after the feeding of the five thousand?', 'Twelve baskets', 'Seven baskets', 'Five baskets', 'Three baskets', 'a', 'John 6:13 — "filled twelve baskets with the fragments."'),
('John', 6, 'teens', 2, 'What did Jesus say to the disciples when they were afraid of Him on the water?', '"It is I; be not afraid"', '"Peace, be still"', '"O ye of little faith"', '"Come to me on the water"', 'a', 'John 6:20 — "It is I; be not afraid."'),
('John', 6, 'teens', 3, 'What title did Jesus give Himself in this chapter about bread?', '"I am the bread of life"', '"I am the door of the sheep"', '"I am the good shepherd"', '"I am the true vine"', 'a', 'John 6:35 — "I am the bread of life."'),
('John', 6, 'teens', 4, 'Why did many of Jesus'' disciples stop following Him after His teaching in this chapter?', 'They said "This is an hard saying; who can hear it?"', 'They were afraid of the Pharisees', 'They wanted to make Him king by force', 'They disagreed about the Sabbath', 'a', 'John 6:60,66 — "Many therefore of his disciples… said, This is an hard saying; who can hear it?" and "many of his disciples went back."'),
('John', 6, 'teens', 5, 'What did Peter say when Jesus asked if the twelve would also leave?', '"Lord, to whom shall we go? thou hast the words of eternal life"', '"We will never leave you, Master"', '"Where else can we find such miracles?"', '"We have given up everything for you"', 'a', 'John 6:68 — "Lord, to whom shall we go? thou hast the words of eternal life."'),
-- Adults
('John', 6, 'adults', 1, 'Which disciple did Jesus test by asking where they could buy bread for the multitude?', 'Philip', 'Andrew', 'Peter', 'John', 'a', 'John 6:5-6 — Jesus asked Philip, "Whence shall we buy bread, that these may eat? And this he said to prove him."'),
('John', 6, 'adults', 2, 'What did the people try to do after witnessing the feeding miracle?', 'Take Jesus by force to make Him a king', 'Bring more sick people for healing', 'Follow Him across the sea', 'Declare Him the new high priest', 'a', 'John 6:15 — "they would come and take him by force, to make him a king."'),
('John', 6, 'adults', 3, 'What does Jesus say is the will of the Father regarding those given to Him?', 'That He should lose nothing, but raise it up again at the last day', 'That they should keep all the commandments', 'That they should preach to every nation', 'That they should fast and pray continually', 'a', 'John 6:39 — "of all which he hath given me I should lose nothing, but should raise it up again at the last day."'),
('John', 6, 'adults', 4, 'What Old Testament comparison did the crowd make, asking Jesus to match it?', 'Their fathers ate manna in the desert — they wanted similar bread from heaven', 'Moses parted the Red Sea — they wanted Him to part the Jordan', 'Elijah called fire from heaven — they wanted a similar sign', 'Joshua stopped the sun — they wanted power over nature', 'a', 'John 6:31 — "Our fathers did eat manna in the desert; as it is written, He gave them bread from heaven to eat."'),
('John', 6, 'adults', 5, 'What does Jesus teach about eating His flesh and drinking His blood in John 6:53-54?', 'Unless you eat His flesh and drink His blood, you have no life — those who do have eternal life', 'It is a commandment to observe the Passover meal in His honor', 'It is symbolic language meaning to follow His teachings', 'It means to fast in remembrance of His sacrifice', 'a', 'John 6:53-54 — "Except ye eat the flesh of the Son of man, and drink his blood, ye have no life in you."'),
('John', 6, 'adults', 6, 'What did Jesus say about those who come to Him and their spiritual state?', '"No man can come to me, except the Father which hath sent me draw him"', '"All who seek shall find, for the door is always open"', '"Those who keep the law are already near to me"', '"Whoever hears the prophets will come to me naturally"', 'a', 'John 6:44 — "No man can come to me, except the Father which hath sent me draw him."'),
('John', 6, 'adults', 7, 'Which disciple did Jesus identify as a devil (betrayer) at the end of chapter 6?', 'Judas Iscariot, though He did not name him directly — John says Jesus spoke of him', 'Peter, for his lack of faith', 'Thomas, for his doubts', 'Bartholomew, for his unbelief', 'a', 'John 6:70-71 — "one of you is a devil… He spake of Judas Iscariot."'),
('John', 6, 'adults', 8, 'How does Jesus contrast the manna of Moses with the true bread from heaven?', 'The fathers ate manna and are dead, but whoever eats the living bread shall live forever', 'The manna sustained only the body, but the true bread heals all diseases', 'The manna was for Israel only, but the bread of life is for the Gentiles', 'The manna was temporary food, but the new bread is the written Word of God', 'a', 'John 6:49-51 — "Your fathers did eat manna in the wilderness, and are dead… if any man eat of this bread, he shall live for ever."'),

-- ═══ John Chapter 7 ═══
-- Kids
('John', 7, 'kids', 1, 'What Jewish feast was happening in this chapter?', 'The Feast of Tabernacles', 'The Passover', 'The Feast of Weeks', 'The Day of Atonement', 'a', 'John 7:2 — "the Jews'' feast of tabernacles was at hand."'),
('John', 7, 'kids', 2, 'What did Jesus offer to anyone who was thirsty?', '"Come unto me, and drink"', '"Go to the river Jordan"', '"Ask the priests for water"', '"Dig a well and find springs"', 'a', 'John 7:37 — "If any man thirst, let him come unto me, and drink."'),
('John', 7, 'kids', 3, 'Did the people all agree about who Jesus was?', 'No, there was a division among the people about Him', 'Yes, everyone believed He was the Christ', 'Yes, everyone thought He was just a teacher', 'No one had an opinion about Him', 'a', 'John 7:43 — "So there was a division among the people because of him."'),
-- Teens
('John', 7, 'teens', 1, 'Why did Jesus'' own brothers tell Him to go to Judaea?', 'They said He should show His works publicly if He wanted followers — they did not believe in Him', 'They wanted Him to be safe with family there', 'They wanted Him to visit the temple for prayer', 'They believed He was the Messiah and should declare it', 'a', 'John 7:3-5 — "His brethren… said unto him… shew thyself to the world. For neither did his brethren believe in him."'),
('John', 7, 'teens', 2, 'How did Jesus go to the feast?', 'Secretly, not openly', 'With a large crowd of followers', 'With His brothers and mother', 'In a public procession', 'a', 'John 7:10 — "then went he also up unto the feast, not openly, but as it were in secret."'),
('John', 7, 'teens', 3, 'What did the officers sent to arrest Jesus say when they returned empty-handed?', '"Never man spake like this man"', '"He escaped before we could reach Him"', '"The crowd protected Him from us"', '"We could not find Him in the temple"', 'a', 'John 7:46 — "The officers answered, Never man spake like this man."'),
('John', 7, 'teens', 4, 'Who spoke up in Jesus'' defense among the Pharisees?', 'Nicodemus', 'Joseph of Arimathaea', 'Gamaliel', 'Simon the Pharisee', 'a', 'John 7:50-51 — "Nicodemus saith unto them… Doth our law judge any man, before it hear him?"'),
('John', 7, 'teens', 5, 'What was the crowd''s debate about Jesus'' origin that caused confusion?', 'Some said Christ comes from Bethlehem, not Galilee, unaware Jesus was born in Bethlehem', 'They argued whether He was from Nazareth or Jerusalem', 'They debated if He was from the tribe of Judah or Levi', 'They disagreed about whether He was a prophet or a priest', 'a', 'John 7:41-42 — "Shall Christ come out of Galilee? Hath not the scripture said, That Christ cometh of the seed of David, and out of the town of Bethlehem?"'),
-- Adults
('John', 7, 'adults', 1, 'What reason did Jesus give for the world''s hatred toward Him?', '"The world… hateth me, because I testify of it, that the works thereof are evil"', '"The world hates me because I am not of this world"', '"They hate me because I come from Galilee"', '"The rulers stir up hatred because they fear losing power"', 'a', 'John 7:7 — "The world… hateth me, because I testify of it, that the works thereof are evil."'),
('John', 7, 'adults', 2, 'What test did Jesus give to know whether His doctrine was from God?', '"If any man will do his will, he shall know of the doctrine"', '"Search the scriptures and compare them to my words"', '"Ask the Father in prayer and He will confirm it"', '"Watch for signs and wonders that follow my teaching"', 'a', 'John 7:17 — "If any man will do his will, he shall know of the doctrine, whether it be of God."'),
('John', 7, 'adults', 3, 'What argument about circumcision and the Sabbath did Jesus use?', 'If circumcision is done on the Sabbath to keep Moses'' law, why are they angry He healed a whole man on the Sabbath?', 'Moses never intended the Sabbath to prevent mercy', 'Abraham circumcised on every day of the week', 'The prophets regularly healed on the Sabbath', 'a', 'John 7:23 — "If a man on the sabbath day receive circumcision… are ye angry at me, because I have made a man every whit whole on the sabbath day?"'),
('John', 7, 'adults', 4, 'What did Jesus promise would flow out of those who believe in Him?', 'Rivers of living water — which John says refers to the Holy Spirit', 'Streams of healing power', 'Words of prophecy and wisdom', 'Songs of praise and thanksgiving', 'a', 'John 7:38-39 — "out of his belly shall flow rivers of living water. But this spake he of the Spirit."'),
('John', 7, 'adults', 5, 'What was Jesus'' response about His time or "hour"?', '"My time is not yet come: but your time is alway ready"', '"The hour approaches when all will be revealed"', '"My time is in the Father''s hands alone"', '"When the feast is over, then my hour will come"', 'a', 'John 7:6 — "My time is not yet come: but your time is alway ready."'),
('John', 7, 'adults', 6, 'According to John 7:15, what amazed the Jews about Jesus'' teaching?', 'He knew letters (Scripture) having never formally studied', 'He spoke with more authority than the scribes', 'He could quote every book of Moses from memory', 'He taught in multiple languages', 'a', 'John 7:15 — "the Jews marvelled, saying, How knoweth this man letters, having never learned?"'),
('John', 7, 'adults', 7, 'What did Jesus cry out on the "last day, that great day of the feast"?', '"If any man thirst, let him come unto me, and drink"', '"I am the light of the world"', '"The hour is come for the Son of man to be glorified"', '"Repent, for the kingdom of heaven is at hand"', 'a', 'John 7:37 — "In the last day, that great day of the feast, Jesus stood and cried, saying, If any man thirst, let him come unto me, and drink."'),
('John', 7, 'adults', 8, 'What principle did Nicodemus cite in defense of Jesus before the Pharisees?', 'Their law does not judge a man before hearing him and knowing what he does', 'The prophets foretold that the Messiah would come from Galilee', 'A man''s works testify to his character', 'The Sanhedrin must have a unanimous vote to condemn', 'a', 'John 7:51 — "Doth our law judge any man, before it hear him, and know what he doeth?"'),

-- ═══ John Chapter 8 ═══
-- Kids
('John', 8, 'kids', 1, 'A woman was brought to Jesus who had done something wrong. What did Jesus say to those who wanted to punish her?', '"He that is without sin among you, let him first cast a stone at her"', '"Take her to the priests for judgment"', '"She must pay a fine"', '"Forgive her and forget about it"', 'a', 'John 8:7 — "He that is without sin among you, let him first cast a stone at her."'),
('John', 8, 'kids', 2, 'What did Jesus call Himself about light?', '"I am the light of the world"', '"I am the morning star"', '"I am the lampstand"', '"I am the candle of God"', 'a', 'John 8:12 — "I am the light of the world."'),
('John', 8, 'kids', 3, 'What did all the accusers do after Jesus spoke to them?', 'They left one by one, beginning with the oldest', 'They threw stones at Jesus instead', 'They asked Jesus to judge the woman', 'They apologized to the woman', 'a', 'John 8:9 — "went out one by one, beginning at the eldest."'),
-- Teens
('John', 8, 'teens', 1, 'After Jesus spoke to the woman''s accusers, who left first?', 'The eldest went out first, then the others one by one', 'The youngest left first out of shame', 'The scribes left, but the Pharisees stayed', 'They all left at the same time', 'a', 'John 8:9 — "they which heard it, being convicted by their own conscience, went out one by one, beginning at the eldest."'),
('John', 8, 'teens', 2, 'What did Jesus tell the woman after her accusers left?', '"Neither do I condemn thee: go, and sin no more"', '"Your sins are forgiven, go in peace"', '"Go and show yourself to the priest"', '"Tell no one what happened here"', 'a', 'John 8:11 — "Neither do I condemn thee: go, and sin no more."'),
('John', 8, 'teens', 3, 'What did Jesus promise to those who continue in His word?', '"Ye shall know the truth, and the truth shall make you free"', '"You shall have treasure in heaven"', '"You shall never be sick again"', '"You shall rule over nations"', 'a', 'John 8:31-32 — "If ye continue in my word… ye shall know the truth, and the truth shall make you free."'),
('John', 8, 'teens', 4, 'What claim about Abraham made the Jews want to stone Jesus?', '"Before Abraham was, I am"', '"I am greater than Abraham"', '"Abraham was my servant"', '"Abraham saw me and worshipped me"', 'a', 'John 8:58-59 — "Before Abraham was, I am. Then took they up stones to cast at him."'),
('John', 8, 'teens', 5, 'What did Jesus say about the devil?', '"He was a murderer from the beginning, and abode not in the truth"', '"He is a fallen angel of the highest order"', '"He was once a servant of God who turned away"', '"He rules the kingdoms of this world temporarily"', 'a', 'John 8:44 — "He was a murderer from the beginning, and abode not in the truth."'),
-- Adults
('John', 8, 'adults', 1, 'What law did the scribes and Pharisees cite regarding the woman caught in adultery?', 'Moses in the law commanded that such should be stoned', 'Moses said adulterers should be put out of the camp', 'The law required two witnesses for a death sentence', 'Moses commanded a certificate of divorce', 'a', 'John 8:5 — "Moses in the law commanded us, that such should be stoned."'),
('John', 8, 'adults', 2, 'When Jesus declared "I am the light of the world," what did He promise to those who follow Him?', 'They shall not walk in darkness but shall have the light of life', 'They shall see the glory of God in the temple', 'They shall perform mighty works in His name', 'They shall be called children of light', 'a', 'John 8:12 — "he that followeth me shall not walk in darkness, but shall have the light of life."'),
('John', 8, 'adults', 3, 'What did Jesus say about His judgment?', '"I judge no man. And yet if I judge, my judgment is true: for I am not alone, but I and the Father that sent me"', '"My judgment is righteous because I know the hearts of all men"', '"I leave all judgment to the Father until the last day"', '"I judge by the law of Moses and the prophets"', 'a', 'John 8:15-16 — "I judge no man. And yet if I judge, my judgment is true: for I am not alone."'),
('John', 8, 'adults', 4, 'What did Jesus say would happen if the Jews did not believe that "I am he"?', '"Ye shall die in your sins"', '"Ye shall be cast out of the synagogue"', '"Ye shall wander without hope"', '"Ye shall face the judgment of Moses"', 'a', 'John 8:24 — "if ye believe not that I am he, ye shall die in your sins."'),
('John', 8, 'adults', 5, 'Whom did Jesus identify as the father of the unbelieving Jews in this chapter?', 'The devil — "Ye are of your father the devil, and the lusts of your father ye will do"', 'Abraham in name only, not in truth', 'Moses, whose law they misunderstand', 'The Pharisees who taught them', 'a', 'John 8:44 — "Ye are of your father the devil."'),
('John', 8, 'adults', 6, 'What did Jesus claim about His relationship to Abraham?', '"Your father Abraham rejoiced to see my day: and he saw it, and was glad"', '"Abraham worshipped me in the tent at Mamre"', '"Abraham received the covenant from my hands"', '"I appeared to Abraham in the burning bush"', 'a', 'John 8:56 — "Your father Abraham rejoiced to see my day: and he saw it, and was glad."'),
('John', 8, 'adults', 7, 'What is the theological significance of Jesus'' statement "Before Abraham was, I am"?', 'It echoes God''s self-revelation as "I AM" in Exodus 3:14, claiming divine pre-existence and deity', 'It simply means Jesus was older than Abraham in heavenly years', 'It refers to Jesus'' foreknowledge of Abraham''s life', 'It is a claim to be a reincarnation of Abraham', 'a', 'John 8:58 — "Before Abraham was, I am" parallels the divine name revealed to Moses (Exodus 3:14).'),
('John', 8, 'adults', 8, 'According to Jesus in John 8:34-36, what is the condition and remedy of those who commit sin?', 'Whoever commits sin is the servant of sin; but if the Son makes you free, you are free indeed', 'Sin leads to death, but the law can save', 'All men sin but the righteous earn their freedom', 'Sin is a disease that can be cured by repentance alone', 'a', 'John 8:34,36 — "Whosoever committeth sin is the servant of sin… If the Son therefore shall make you free, ye shall be free indeed."'),

-- ═══ John Chapter 9 ═══
-- Kids
('John', 9, 'kids', 1, 'What was wrong with the man Jesus healed in this chapter?', 'He was born blind', 'He could not walk', 'He was deaf', 'He had leprosy', 'a', 'John 9:1 — "a man which was blind from his birth."'),
('John', 9, 'kids', 2, 'What did Jesus put on the blind man''s eyes?', 'Clay made from spit and dirt', 'Oil from a lamp', 'Water from the well', 'Ashes from the altar', 'a', 'John 9:6 — "he spat on the ground, and made clay of the spittle, and he anointed the eyes of the blind man with the clay."'),
('John', 9, 'kids', 3, 'Where did Jesus tell the blind man to go and wash?', 'The pool of Siloam', 'The river Jordan', 'The Sea of Galilee', 'The pool of Bethesda', 'a', 'John 9:7 — "Go, wash in the pool of Siloam."'),
-- Teens
('John', 9, 'teens', 1, 'Why did the disciples think the man was born blind?', 'They asked if it was because of his sin or his parents'' sin', 'They thought he had been cursed by a priest', 'They believed he had offended God in a past life', 'They thought his mother had been near an unclean animal', 'a', 'John 9:2 — "who did sin, this man, or his parents, that he was born blind?"'),
('John', 9, 'teens', 2, 'What did Jesus say was the real reason the man was born blind?', '"That the works of God should be made manifest in him"', '"Because of the sins of his ancestors"', '"To teach his parents humility"', '"As punishment for a future sin"', 'a', 'John 9:3 — "Neither hath this man sinned, nor his parents: but that the works of God should be made manifest in him."'),
('John', 9, 'teens', 3, 'What did the healed man say to the Pharisees about his experience?', '"One thing I know, that, whereas I was blind, now I see"', '"Jesus is the greatest prophet who ever lived"', '"I have never seen such a miracle before"', '"My eyes were opened by the power of God alone"', 'a', 'John 9:25 — "One thing I know, that, whereas I was blind, now I see."'),
('John', 9, 'teens', 4, 'What happened to the healed man when he confessed Jesus?', 'The Pharisees cast him out of the synagogue', 'The Pharisees praised him for his faith', 'He was arrested and put in prison', 'He was sent to the high priest for questioning', 'a', 'John 9:34 — "they cast him out."'),
('John', 9, 'teens', 5, 'When Jesus found the man after he was cast out, what did the man do?', 'He worshipped Jesus after learning He was the Son of God', 'He asked Jesus to heal others too', 'He went and told the whole city', 'He asked to become one of Jesus'' disciples', 'a', 'John 9:38 — "Lord, I believe. And he worshipped him."'),
-- Adults
('John', 9, 'adults', 1, 'What did Jesus say about working while it is day?', '"I must work the works of him that sent me, while it is day: the night cometh, when no man can work"', '"Work while the harvest is plentiful and the laborers are few"', '"Do the Father''s will before the Sabbath comes"', '"Make haste, for my hour is drawing near"', 'a', 'John 9:4 — "I must work the works of him that sent me, while it is day: the night cometh, when no man can work."'),
('John', 9, 'adults', 2, 'What meaning does John give for the name "Siloam"?', 'Sent', 'Healed', 'Washed', 'Chosen', 'a', 'John 9:7 — "the pool of Siloam, (which is by interpretation, Sent)."'),
('John', 9, 'adults', 3, 'Why were the Pharisees divided about Jesus after this healing?', 'Some said He was not from God because He broke the Sabbath; others asked how a sinner could do such miracles', 'Some wanted to follow Him; others wanted to arrest Him', 'Some said He was Moses; others said He was Elijah', 'Some praised God; others blamed the devil', 'a', 'John 9:16 — "some of the Pharisees said, This man is not of God, because he keepeth not the sabbath day. Others said, How can a man that is a sinner do such miracles?"'),
('John', 9, 'adults', 4, 'Why did the healed man''s parents refuse to explain how he could now see?', 'They feared the Jews, who had agreed to put out of the synagogue anyone who confessed Christ', 'They did not believe their son had truly been blind', 'They were ashamed of their son''s association with Jesus', 'They had been told by the priests not to speak', 'a', 'John 9:22 — "because they feared the Jews: for the Jews had agreed already, that if any man did confess that he was Christ, he should be put out of the synagogue."'),
('John', 9, 'adults', 5, 'What ironic statement did the healed man make to the Pharisees about Jesus'' origin?', '"Herein is a marvellous thing, that ye know not from whence he is, and yet he hath opened mine eyes"', '"You claim to know the law but cannot see the truth"', '"If He were not from God, how could He do this?"', '"Even a blind man can see that God is with Him"', 'a', 'John 9:30 — "Herein is a marvellous thing, that ye know not from whence he is, and yet he hath opened mine eyes."'),
('John', 9, 'adults', 6, 'What statement does Jesus make about spiritual blindness at the end of chapter 9?', '"If ye were blind, ye should have no sin: but now ye say, We see; therefore your sin remaineth"', '"Those who are blind shall see, and those who see shall stumble"', '"The blind are blessed for they walk by faith"', '"Your blindness is self-imposed and cannot be healed"', 'a', 'John 9:41 — "If ye were blind, ye should have no sin: but now ye say, We see; therefore your sin remaineth."'),
('John', 9, 'adults', 7, 'What did Jesus declare about Himself at the beginning of this episode?', '"As long as I am in the world, I am the light of the world"', '"I have come to give sight to all who believe"', '"The Father has sent me to heal the blind"', '"I am the door through which the blind shall see"', 'a', 'John 9:5 — "As long as I am in the world, I am the light of the world."'),
('John', 9, 'adults', 8, 'What theological principle did the Pharisees claim about Jesus that the healed man challenged?', 'They said "we know that this man is a sinner" — the healed man replied that God does not hear sinners but hears those who worship Him and do His will', 'They said He was possessed by a demon — the man said demons cannot open blind eyes', 'They said He was from Nazareth — the man said the Messiah''s birthplace does not matter', 'They said He had no authority — the man said His works proved His authority', 'a', 'John 9:24,31 — "We know that this man is a sinner… Now we know that God heareth not sinners: but if any man be a worshipper of God, and doeth his will, him he heareth."'),

-- ═══ John Chapter 10 ═══
-- Kids
('John', 10, 'kids', 1, 'What did Jesus call Himself in this chapter about a shepherd?', '"I am the good shepherd"', '"I am the great king"', '"I am the wise teacher"', '"I am the mighty warrior"', 'a', 'John 10:11 — "I am the good shepherd."'),
('John', 10, 'kids', 2, 'What does the good shepherd do for his sheep?', 'He gives his life for the sheep', 'He buys them new pastures', 'He builds them a big barn', 'He gives them golden bells', 'a', 'John 10:11 — "the good shepherd giveth his life for the sheep."'),
('John', 10, 'kids', 3, 'What did Jesus say about His sheep knowing Him?', 'His sheep hear His voice and follow Him', 'His sheep wear a special mark', 'His sheep are the strongest in the flock', 'His sheep stay in one place forever', 'a', 'John 10:27 — "My sheep hear my voice, and I know them, and they follow me."'),
-- Teens
('John', 10, 'teens', 1, 'What two "I am" statements does Jesus make in this chapter?', '"I am the door" and "I am the good shepherd"', '"I am the way" and "I am the truth"', '"I am the bread" and "I am the vine"', '"I am the resurrection" and "I am the life"', 'a', 'John 10:7,11 — "I am the door of the sheep" and "I am the good shepherd."'),
('John', 10, 'teens', 2, 'What is the difference between the good shepherd and a hireling (hired worker)?', 'The hireling flees when the wolf comes; the shepherd lays down his life', 'The hireling feeds the sheep poorly; the shepherd gives them the best', 'The hireling ignores sick sheep; the shepherd heals them', 'The hireling keeps the sheep inside; the shepherd lets them roam free', 'a', 'John 10:12-13 — "he that is an hireling… seeth the wolf coming, and leaveth the sheep, and fleeth."'),
('John', 10, 'teens', 3, 'What did Jesus say about having "other sheep"?', 'He has other sheep not of this fold — He must bring them also, and there shall be one fold and one shepherd', 'He has sheep in every nation who already believe in Him', 'He will create new sheep in the age to come', 'He has sheep that even the disciples do not know about', 'a', 'John 10:16 — "other sheep I have, which are not of this fold: them also I must bring… and there shall be one fold, and one shepherd."'),
('John', 10, 'teens', 4, 'What bold claim did Jesus make that caused the Jews to take up stones?', '"I and my Father are one"', '"I am greater than Moses"', '"I existed before the world was made"', '"I will destroy the temple and rebuild it"', 'a', 'John 10:30-31 — "I and my Father are one. Then the Jews took up stones again to stone him."'),
('John', 10, 'teens', 5, 'What promise does Jesus give about eternal security in John 10:28-29?', 'No one shall pluck His sheep out of His hand or the Father''s hand', 'His sheep will never face any danger or trial', 'His sheep will live forever on earth', 'His sheep will always be prosperous and healthy', 'a', 'John 10:28-29 — "neither shall any man pluck them out of my hand… no man is able to pluck them out of my Father''s hand."'),
-- Adults
('John', 10, 'adults', 1, 'What does Jesus say the thief comes to do in contrast to His own purpose?', 'The thief comes to steal, kill, and destroy; Jesus came that they might have life more abundantly', 'The thief scatters the sheep; Jesus gathers them', 'The thief breaks down the walls; Jesus builds them up', 'The thief deceives with lies; Jesus teaches truth', 'a', 'John 10:10 — "The thief cometh not, but for to steal, and to kill, and to destroy: I am come that they might have life, and that they might have it more abundantly."'),
('John', 10, 'adults', 2, 'What Scripture did Jesus quote from the Psalms to defend His claim of deity?', '"I said, Ye are gods" from Psalm 82:6 — arguing that if Scripture called human judges gods, He is justified in calling Himself the Son of God', '"The Lord said unto my Lord, Sit thou at my right hand" from Psalm 110', '"Thou art a priest for ever after the order of Melchizedek" from Psalm 110', '"The stone which the builders refused is become the head stone" from Psalm 118', 'a', 'John 10:34-36 — "Is it not written in your law, I said, Ye are gods?" (Psalm 82:6).'),
('John', 10, 'adults', 3, 'What does Jesus say about His authority to lay down His life?', '"No man taketh it from me, but I lay it down of myself. I have power to lay it down, and I have power to take it again"', '"The Father will take my life when the appointed time comes"', '"I surrender my life as a ransom for many"', '"My life is in the Father''s hands, not my own"', 'a', 'John 10:18 — "No man taketh it from me, but I lay it down of myself."'),
('John', 10, 'adults', 4, 'During which feast did the Jews surround Jesus in Solomon''s porch and demand He plainly say if He was the Christ?', 'The Feast of Dedication (Hanukkah)', 'The Feast of Tabernacles', 'The Passover', 'The Feast of Weeks (Pentecost)', 'a', 'John 10:22-24 — "it was at Jerusalem the feast of the dedication, and it was winter."'),
('John', 10, 'adults', 5, 'What evidence did Jesus point to when asked if He was the Christ?', 'The works He did in His Father''s name bear witness of Him', 'The testimony of John the Baptist who declared Him Messiah', 'The fulfillment of Old Testament prophecies in His life', 'The voice of God that spoke at His baptism', 'a', 'John 10:25 — "the works that I do in my Father''s name, they bear witness of me."'),
('John', 10, 'adults', 6, 'Why did Jesus say the unbelieving Jews could not believe?', '"Ye believe not, because ye are not of my sheep"', '"Ye are blinded by the traditions of men"', '"Ye have not been chosen by the Father"', '"Ye love darkness rather than light"', 'a', 'John 10:26 — "ye believe not, because ye are not of my sheep."'),
('John', 10, 'adults', 7, 'Where did Jesus go after the Jews tried to stone Him at the Feast of Dedication?', 'Beyond Jordan, to the place where John first baptized', 'To Galilee to avoid the Jewish leaders', 'To Bethany near Jerusalem', 'To the wilderness of Judaea', 'a', 'John 10:40 — "went away again beyond Jordan into the place where John at first baptized."'),
('John', 10, 'adults', 8, 'What did many people say about Jesus when He was beyond Jordan?', '"John did no miracle: but all things that John spake of this man were true" — and many believed', '"This is truly the prophet that Moses foretold"', '"He is the king of Israel who was promised"', '"His miracles prove He is from God"', 'a', 'John 10:41-42 — "John did no miracle: but all things that John spake of this man were true. And many believed on him there."');

-- ═══════════════════════════════════════════════════════════════════════════
-- CHAPTERS 11 – 15
-- ═══════════════════════════════════════════════════════════════════════════

-- ═══ John Chapter 11 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('John', 11, 'kids', 1, 'Who did Jesus raise from the dead in this chapter?', 'Lazarus', 'Peter', 'Nicodemus', 'Thomas', 'a', 'John 11:43-44 — Jesus called Lazarus out of the grave.'),
('John', 11, 'kids', 2, 'What is the shortest verse in the Bible, found in this chapter?', '"Jesus wept"', '"God is love"', '"Pray always"', '"Be still"', 'a', 'John 11:35 — "Jesus wept."'),
('John', 11, 'kids', 3, 'How many days had Lazarus been in the grave before Jesus arrived?', 'Four days', 'Two days', 'One day', 'Seven days', 'a', 'John 11:17 — "he had lain in the grave four days already."'),
-- Teens
('John', 11, 'teens', 1, 'Who were the two sisters of Lazarus?', 'Martha and Mary', 'Elizabeth and Anna', 'Salome and Joanna', 'Ruth and Naomi', 'a', 'John 11:1 — "Lazarus, of Bethany, the town of Mary and her sister Martha."'),
('John', 11, 'teens', 2, 'What great "I am" statement did Jesus make to Martha?', '"I am the resurrection, and the life"', '"I am the way, the truth, and the life"', '"I am the bread of life"', '"I am the good shepherd"', 'a', 'John 11:25 — "I am the resurrection, and the life."'),
('John', 11, 'teens', 3, 'What did Martha say she believed about Lazarus before Jesus raised him?', 'He would rise again in the resurrection at the last day', 'He was in heaven with Abraham', 'He would sleep until the Messiah came', 'He would be reincarnated in a new body', 'a', 'John 11:24 — "I know that he shall rise again in the resurrection at the last day."'),
('John', 11, 'teens', 4, 'What did Jesus say to Lazarus at the tomb?', '"Lazarus, come forth"', '"Arise and live again"', '"Be healed in the name of God"', '"Return from the dead, my friend"', 'a', 'John 11:43 — "he cried with a loud voice, Lazarus, come forth."'),
('John', 11, 'teens', 5, 'What did the high priest Caiaphas unintentionally prophesy?', 'That Jesus should die for the nation, so the whole nation would not perish', 'That Jesus would destroy the temple and rebuild it', 'That Jesus would become the king of Israel', 'That Jesus would lead the Jews out of Roman bondage', 'a', 'John 11:50-51 — "it is expedient for us, that one man should die for the people, and that the whole nation perish not."'),
-- Adults
('John', 11, 'adults', 1, 'Why did Jesus intentionally delay going to Bethany after hearing Lazarus was sick?', 'He said "This sickness is not unto death, but for the glory of God" — and He stayed two more days', 'He was occupied with teaching in the temple', 'He was waiting for a sign from the Father', 'He wanted to travel safely by night', 'a', 'John 11:4,6 — "This sickness is not unto death, but for the glory of God… he abode two days still in the same place."'),
('John', 11, 'adults', 2, 'What did Thomas say to the other disciples about going to Judaea with Jesus?', '"Let us also go, that we may die with him"', '"We must trust that the Father will protect us"', '"It is too dangerous; we should stay here"', '"Let us wait until the feast is over"', 'a', 'John 11:16 — "Then said Thomas… Let us also go, that we may die with him."'),
('John', 11, 'adults', 3, 'What did Martha say to Jesus that showed she still had faith despite Lazarus''s death?', '"Even now, whatsoever thou wilt ask of God, God will give it thee"', '"If thou hadst been here, none of this would have happened"', '"I believe you can do all things"', '"The Father always hears your prayers"', 'a', 'John 11:22 — "But I know, that even now, whatsoever thou wilt ask of God, God will give it thee."'),
('John', 11, 'adults', 4, 'What practical objection did Martha raise when Jesus said to remove the stone from the tomb?', '"Lord, by this time he stinketh: for he hath been dead four days"', '"The stone is too heavy for us to move"', '"It is not lawful to open a tomb on this day"', '"The body has already been prepared for burial"', 'a', 'John 11:39 — "Lord, by this time he stinketh: for he hath been dead four days."'),
('John', 11, 'adults', 5, 'What did Jesus pray aloud at the tomb, and why?', 'He thanked the Father for hearing Him, and said He spoke aloud so the people would believe the Father sent Him', 'He asked the Father for power to raise the dead', 'He recited a psalm of deliverance', 'He called upon the angels to open the grave', 'a', 'John 11:41-42 — "Father, I thank thee that thou hast heard me… because of the people which stand by I said it, that they may believe that thou hast sent me."'),
('John', 11, 'adults', 6, 'According to John, what broader prophecy did Caiaphas unknowingly make beyond the Jewish nation?', 'That Jesus would die not for the nation only, but to gather together in one the children of God scattered abroad', 'That Jesus would establish a new covenant for all peoples', 'That the temple would be destroyed and a spiritual one raised', 'That the Gentiles would also receive the law of Moses', 'a', 'John 11:52 — "not for that nation only, but that also he should gather together in one the children of God that were scattered abroad."'),
('John', 11, 'adults', 7, 'What was the immediate political result of the raising of Lazarus?', 'The chief priests and Pharisees convened a council and plotted to put Jesus to death', 'The Romans sent soldiers to arrest Jesus', 'Herod ordered Jesus brought before him', 'The Sanhedrin declared Jesus a false prophet', 'a', 'John 11:47,53 — "Then gathered the chief priests and the Pharisees a council… from that day forth they took counsel together for to put him to death."'),
('John', 11, 'adults', 8, 'Where did Jesus withdraw to after the council plotted against Him?', 'A city called Ephraim near the wilderness, with His disciples', 'Galilee, to the region of Capernaum', 'Beyond Jordan where John had baptized', 'The desert of Judaea for forty days', 'a', 'John 11:54 — "Jesus… went thence unto a country near to the wilderness, into a city called Ephraim, and there continued with his disciples."'),

-- ═══ John Chapter 12 ═══
-- Kids
('John', 12, 'kids', 1, 'What did Mary pour on Jesus'' feet?', 'Very costly ointment (spikenard)', 'Olive oil', 'Water from a well', 'Honey', 'a', 'John 12:3 — "Mary took a pound of ointment of spikenard, very costly, and anointed the feet of Jesus."'),
('John', 12, 'kids', 2, 'What animal did Jesus ride into Jerusalem?', 'A young donkey', 'A horse', 'A camel', 'A mule', 'a', 'John 12:14 — "Jesus, when he had found a young ass, sat thereon."'),
('John', 12, 'kids', 3, 'What did the crowd wave and shout when Jesus entered Jerusalem?', 'Palm branches, shouting "Hosanna!"', 'Flags and trumpets', 'Banners and harps', 'Olive branches, shouting "Hallelujah!"', 'a', 'John 12:13 — "Took branches of palm trees, and went forth to meet him, and cried, Hosanna."'),
-- Teens
('John', 12, 'teens', 1, 'Who complained about the expensive ointment being wasted on Jesus?', 'Judas Iscariot', 'Peter', 'Thomas', 'Philip', 'a', 'John 12:4-5 — "Then saith one of his disciples, Judas Iscariot… Why was not this ointment sold?"'),
('John', 12, 'teens', 2, 'What was the real reason Judas complained about the ointment?', 'He was a thief and held the money bag', 'He thought the money should go to the temple', 'He was jealous of Mary''s devotion', 'He genuinely cared about the poor', 'a', 'John 12:6 — "he was a thief, and had the bag, and bare what was put therein."'),
('John', 12, 'teens', 3, 'What illustration about grain did Jesus use to describe His coming death?', '"Except a corn of wheat fall into the ground and die, it abideth alone: but if it die, it bringeth forth much fruit"', '"The wheat and the tares grow together until the harvest"', '"A sower went forth to sow, and some fell on good ground"', '"First the blade, then the ear, then the full corn"', 'a', 'John 12:24 — "Except a corn of wheat fall into the ground and die, it abideth alone: but if it die, it bringeth forth much fruit."'),
('John', 12, 'teens', 4, 'Who came seeking Jesus during the Passover feast?', 'Certain Greeks who wanted to see Jesus', 'Roman soldiers looking for a healer', 'Samaritan pilgrims seeking a prophet', 'Egyptian travelers who heard of His fame', 'a', 'John 12:20-21 — "certain Greeks… came… saying, Sir, we would see Jesus."'),
('John', 12, 'teens', 5, 'What did the voice from heaven say when Jesus prayed?', '"I have both glorified it, and will glorify it again"', '"This is my beloved Son, hear him"', '"I am well pleased with thee"', '"Be strong and of good courage"', 'a', 'John 12:28 — "Then came there a voice from heaven, saying, I have both glorified it, and will glorify it again."'),
-- Adults
('John', 12, 'adults', 1, 'How much was the ointment of spikenard worth, according to Judas?', 'Three hundred pence (about a year''s wages)', 'One hundred pence', 'Fifty pence', 'Five hundred pence', 'a', 'John 12:5 — "Why was not this ointment sold for three hundred pence?"'),
('John', 12, 'adults', 2, 'What did Jesus say Mary''s anointing was for?', '"Against the day of my burying hath she kept this"', '"She has done this as an act of worship"', '"She anoints me as king of Israel"', '"This is a sign of the coming kingdom"', 'a', 'John 12:7 — "against the day of my burying hath she kept this."'),
('John', 12, 'adults', 3, 'Why did the chief priests also plan to put Lazarus to death?', 'Because many Jews believed on Jesus because of Lazarus''s resurrection', 'Because Lazarus was preaching about Jesus', 'Because Lazarus challenged the authority of the priests', 'Because Lazarus refused to return to the synagogue', 'a', 'John 12:10-11 — "the chief priests consulted that they might put Lazarus also to death; Because that by reason of him many of the Jews… believed on Jesus."'),
('John', 12, 'adults', 4, 'What Old Testament prophecy did the crowd''s actions at the triumphal entry fulfill?', '"Fear not, daughter of Sion: behold, thy King cometh, sitting on an ass''s colt" (Zechariah 9:9)', '"Behold, I send my messenger before thy face" (Malachi 3:1)', '"The sceptre shall not depart from Judah" (Genesis 49:10)', '"A star shall come out of Jacob" (Numbers 24:17)', 'a', 'John 12:15 — "Fear not, daughter of Sion: behold, thy King cometh, sitting on an ass''s colt."'),
('John', 12, 'adults', 5, 'What did Jesus say about what would happen when He was "lifted up from the earth"?', '"I, if I be lifted up from the earth, will draw all men unto me"', '"The heavens shall open and the angels descend"', '"The temple shall be destroyed and rebuilt"', '"All nations shall come and worship before me"', 'a', 'John 12:32 — "And I, if I be lifted up from the earth, will draw all men unto me."'),
('John', 12, 'adults', 6, 'What does John say about why many rulers who believed in Jesus did not confess Him?', 'They loved the praise of men more than the praise of God, and feared being put out of the synagogue', 'They did not yet fully understand His teaching', 'They were waiting for the right political moment', 'They feared Roman retaliation', 'a', 'John 12:42-43 — "because of the Pharisees they did not confess him, lest they should be put out of the synagogue: For they loved the praise of men more than the praise of God."'),
('John', 12, 'adults', 7, 'What did Jesus say about the purpose of the voice from heaven?', '"This voice came not because of me, but for your sakes"', '"The Father speaks so that you may fear Him"', '"This voice confirms my authority as the Son"', '"The voice is a sign of the coming judgment"', 'a', 'John 12:30 — "This voice came not because of me, but for your sakes."'),
('John', 12, 'adults', 8, 'What prophecy of Isaiah does John quote to explain the Jews'' unbelief?', '"He hath blinded their eyes, and hardened their heart" (Isaiah 6:10, also Isaiah 53:1)', '"The people that walked in darkness have seen a great light" (Isaiah 9:2)', '"Who hath believed our report?" (Isaiah 53:1)', '"Hear ye indeed, but understand not" (Isaiah 6:9)', 'c', 'John 12:38-40 — John quotes both Isaiah 53:1 ("Lord, who hath believed our report?") and Isaiah 6:10 ("He hath blinded their eyes, and hardened their heart"). The primary verse cited is Isaiah 53:1.'),

-- ═══ John Chapter 13 ═══
-- Kids
('John', 13, 'kids', 1, 'What did Jesus do for His disciples at the Last Supper?', 'He washed their feet', 'He cooked them a meal', 'He gave them new clothes', 'He read them a story', 'a', 'John 13:5 — Jesus "began to wash the disciples'' feet."'),
('John', 13, 'kids', 2, 'What new commandment did Jesus give His disciples?', '"Love one another"', '"Pray every day"', '"Read the Scriptures"', '"Build a church"', 'a', 'John 13:34 — "A new commandment I give unto you, That ye love one another."'),
('John', 13, 'kids', 3, 'Who did Jesus say would betray Him?', 'Judas (the one who received the piece of bread)', 'Peter', 'Thomas', 'Andrew', 'a', 'John 13:26 — Jesus gave the sop to Judas Iscariot, identifying him as the betrayer.'),
-- Teens
('John', 13, 'teens', 1, 'Which disciple first refused to let Jesus wash his feet?', 'Peter', 'James', 'John', 'Thomas', 'a', 'John 13:6-8 — Peter said "Thou shalt never wash my feet."'),
('John', 13, 'teens', 2, 'What did Jesus say to Peter when he refused the foot-washing?', '"If I wash thee not, thou hast no part with me"', '"You must obey your Master"', '"This is a command, not a request"', '"Do not be proud, Simon"', 'a', 'John 13:8 — "If I wash thee not, thou hast no part with me."'),
('John', 13, 'teens', 3, 'How did Jesus identify who would betray Him?', 'He dipped a piece of bread (sop) and gave it to Judas', 'He pointed directly at Judas', 'He whispered the name to Peter', 'He said the betrayer''s name aloud', 'a', 'John 13:26 — "He it is, to whom I shall give a sop, when I have dipped it."'),
('John', 13, 'teens', 4, 'What did Jesus say to Judas after giving him the bread?', '"That thou doest, do quickly"', '"Leave this place and never return"', '"You will regret this betrayal"', '"Go and fulfill your destiny"', 'a', 'John 13:27 — "That thou doest, do quickly."'),
('John', 13, 'teens', 5, 'What did Jesus say people would know His disciples by?', 'By their love for one another', 'By their great miracles', 'By their knowledge of Scripture', 'By their obedience to the law', 'a', 'John 13:35 — "By this shall all men know that ye are my disciples, if ye have love one to another."'),
-- Adults
('John', 13, 'adults', 1, 'What does John 13:1 say about Jesus'' knowledge as the Passover approached?', 'Jesus knew His hour was come to depart out of this world unto the Father', 'Jesus knew the Pharisees were planning His arrest', 'Jesus knew He must go to the garden to pray', 'Jesus knew the disciples would all forsake Him', 'a', 'John 13:1 — "Jesus knew that his hour was come that he should depart out of this world unto the Father."'),
('John', 13, 'adults', 2, 'What had the devil already done before the foot-washing, according to John?', 'Put into the heart of Judas Iscariot to betray Jesus', 'Tempted Peter to deny Jesus', 'Scattered the disciples in fear', 'Entered the Sanhedrin to plot Jesus'' death', 'a', 'John 13:2 — "the devil having now put into the heart of Judas Iscariot, Simon''s son, to betray him."'),
('John', 13, 'adults', 3, 'After Peter changed his mind and asked for a full washing, what did Jesus say?', '"He that is washed needeth not save to wash his feet, but is clean every whit"', '"I will wash you from head to toe as you wish"', '"Only your hands and feet need washing"', '"The one who is clean needs no washing at all"', 'a', 'John 13:10 — "He that is washed needeth not save to wash his feet, but is clean every whit."'),
('John', 13, 'adults', 4, 'What lesson did Jesus draw from the foot-washing?', '"If I then, your Lord and Master, have washed your feet; ye also ought to wash one another''s feet"', '"A servant is greater than his master when he serves"', '"Cleanliness is next to godliness"', '"The last shall be first in the kingdom"', 'a', 'John 13:14 — "If I then, your Lord and Master, have washed your feet; ye also ought to wash one another''s feet."'),
('John', 13, 'adults', 5, 'What Scripture did Jesus say was fulfilled by His betrayal?', '"He that eateth bread with me hath lifted up his heel against me" (Psalm 41:9)', '"They weighed for my price thirty pieces of silver" (Zechariah 11:12)', '"My own familiar friend hath dealt treacherously" (Psalm 55:12-13)', '"He was numbered with the transgressors" (Isaiah 53:12)', 'a', 'John 13:18 — "He that eateth bread with me hath lifted up his heel against me."'),
('John', 13, 'adults', 6, 'Which disciple was leaning on Jesus'' bosom at supper?', 'The disciple whom Jesus loved (traditionally identified as John)', 'Peter', 'Andrew', 'James', 'a', 'John 13:23 — "there was leaning on Jesus'' bosom one of his disciples, whom Jesus loved."'),
('John', 13, 'adults', 7, 'What did the other disciples think Judas was leaving to do?', 'Buy things needed for the feast or give something to the poor (since he had the money bag)', 'Go pray at the temple', 'Fetch more wine for the supper', 'Meet with the chief priests about a legitimate matter', 'a', 'John 13:29 — "some of them thought… that Judas had the bag, that Jesus had said unto him, Buy those things that we have need of against the feast; or, that he should give something to the poor."'),
('John', 13, 'adults', 8, 'What did Jesus predict about Peter at the end of chapter 13?', 'Peter would deny Him three times before the cock crowed', 'Peter would betray Him to the Pharisees', 'Peter would fall asleep during His hour of trial', 'Peter would flee to Galilee that night', 'a', 'John 13:38 — "The cock shall not crow, till thou hast denied me thrice."'),

-- ═══ John Chapter 14 ═══
-- Kids
('John', 14, 'kids', 1, 'What did Jesus say He was going to prepare for His disciples?', 'A place in His Father''s house (many mansions)', 'A new boat for fishing', 'A special meal', 'A crown of gold', 'a', 'John 14:2 — "In my Father''s house are many mansions… I go to prepare a place for you."'),
('John', 14, 'kids', 2, 'What three things did Jesus say He is?', 'The way, the truth, and the life', 'The bread, the water, and the light', 'The king, the priest, and the prophet', 'The father, the son, and the spirit', 'a', 'John 14:6 — "I am the way, the truth, and the life."'),
('John', 14, 'kids', 3, 'What helper did Jesus promise to send to His disciples?', 'The Comforter (Holy Spirit)', 'A mighty angel', 'A new prophet', 'A strong army', 'a', 'John 14:26 — "the Comforter, which is the Holy Ghost."'),
-- Teens
('John', 14, 'teens', 1, 'According to Jesus, how can a person come to the Father?', 'Only through Jesus — "no man cometh unto the Father, but by me"', 'Through keeping the law of Moses', 'Through the prayers of the priests', 'Through any sincere religious practice', 'a', 'John 14:6 — "no man cometh unto the Father, but by me."'),
('John', 14, 'teens', 2, 'What did Jesus say to comfort His disciples about His departure?', '"Let not your heart be troubled: ye believe in God, believe also in me"', '"Do not weep, for I will return tomorrow"', '"Be strong and carry on my work"', '"The world will treat you well after I go"', 'a', 'John 14:1 — "Let not your heart be troubled: ye believe in God, believe also in me."'),
('John', 14, 'teens', 3, 'What did Jesus promise the Comforter (Holy Spirit) would do?', 'Teach them all things and bring to remembrance all that Jesus had said', 'Give them power to perform great miracles', 'Make them rulers over Israel', 'Protect them from all physical harm', 'a', 'John 14:26 — "he shall teach you all things, and bring all things to your remembrance, whatsoever I have said unto you."'),
('John', 14, 'teens', 4, 'What did Philip ask Jesus?', '"Lord, shew us the Father, and it sufficeth us"', '"Lord, teach us to pray"', '"Lord, how can we know the way?"', '"Lord, who is the greatest among us?"', 'a', 'John 14:8 — "Philip saith unto him, Lord, shew us the Father, and it sufficeth us."'),
('John', 14, 'teens', 5, 'What kind of peace did Jesus say He gives, different from the world''s?', '"My peace I give unto you: not as the world giveth, give I unto you"', '"I give you peace through prosperity and success"', '"I give you peace by removing all your enemies"', '"I give you the peace of never having to work again"', 'a', 'John 14:27 — "Peace I leave with you, my peace I give unto you: not as the world giveth, give I unto you."'),
-- Adults
('John', 14, 'adults', 1, 'What did Jesus say about the relationship between seeing Him and seeing the Father?', '"He that hath seen me hath seen the Father" — the Father dwells in Him', 'The Father is invisible and cannot be seen through any means', 'The Father will appear separately at the end of time', 'One must die first to see the Father face to face', 'a', 'John 14:9 — "he that hath seen me hath seen the Father."'),
('John', 14, 'adults', 2, 'What does Jesus say about the works His believers will do?', 'They shall do the works He does, and greater works, because He goes to the Father', 'They shall do lesser works as humble servants', 'They shall only teach and preach, not do miracles', 'They shall do the same works but nothing greater', 'a', 'John 14:12 — "the works that I do shall he do also; and greater works than these shall he do; because I go unto my Father."'),
('John', 14, 'adults', 3, 'What condition does Jesus give for answered prayer in this chapter?', '"If ye shall ask any thing in my name, I will do it"', '"If you fast and pray with a pure heart"', '"If you first reconcile with your brother"', '"If you pray in the temple at the appointed hour"', 'a', 'John 14:14 — "If ye shall ask any thing in my name, I will do it."'),
('John', 14, 'adults', 4, 'What does Jesus call the Holy Spirit in John 14:16-17?', 'Another Comforter — the Spirit of truth, whom the world cannot receive', 'The Spirit of power that will come upon them', 'The angel of the Lord who will guard them', 'The spirit of prophecy that will reveal the future', 'a', 'John 14:16-17 — "another Comforter… even the Spirit of truth; whom the world cannot receive."'),
('John', 14, 'adults', 5, 'What did Jesus say about the person who loves Him regarding the Father?', '"He that loveth me shall be loved of my Father, and I will love him, and will manifest myself to him"', '"He shall sit at the right hand of the Father"', '"He shall be called a friend of God"', '"He shall never face judgment"', 'a', 'John 14:21 — "he that loveth me shall be loved of my Father, and I will love him, and will manifest myself to him."'),
('John', 14, 'adults', 6, 'What question did Judas (not Iscariot) ask Jesus?', '"Lord, how is it that thou wilt manifest thyself unto us, and not unto the world?"', '"Lord, when will thou restore the kingdom to Israel?"', '"Lord, which of us is the greatest?"', '"Lord, shall we call fire down from heaven?"', 'a', 'John 14:22 — "Judas saith unto him, not Iscariot, Lord, how is it that thou wilt manifest thyself unto us, and not unto the world?"'),
('John', 14, 'adults', 7, 'What does Jesus say about His relationship to the Father near the end of the chapter?', '"The Father is greater than I"', '"The Father and I are the same being"', '"The Father has given me all His authority permanently"', '"The Father works through me but we are separate"', 'a', 'John 14:28 — "my Father is greater than I."'),
('John', 14, 'adults', 8, 'What reason does Jesus give for telling His disciples about His departure beforehand?', '"I have told you before it come to pass, that, when it is come to pass, ye might believe"', '"So that you can prepare yourselves for tribulation"', '"So that you can tell others what will happen"', '"So that you will not be afraid of the Romans"', 'a', 'John 14:29 — "now I have told you before it come to pass, that, when it is come to pass, ye might believe."'),

-- ═══ John Chapter 15 ═══
-- Kids
('John', 15, 'kids', 1, 'What did Jesus compare Himself to in this chapter?', 'A vine — "I am the true vine"', 'A tree — "I am the tallest tree"', 'A flower — "I am the beautiful rose"', 'A river — "I am the flowing river"', 'a', 'John 15:1 — "I am the true vine."'),
('John', 15, 'kids', 2, 'What word did Jesus repeat many times, telling His disciples to stay connected to Him?', '"Abide" (stay close to me)', '"Run" (run to me)', '"Sing" (sing to me)', '"Sleep" (rest in me)', 'a', 'John 15:4 — "Abide in me, and I in you."'),
('John', 15, 'kids', 3, 'What is the greatest kind of love, according to Jesus?', 'When someone gives up their life for their friends', 'When someone gives all their money away', 'When someone is nice to strangers', 'When someone prays all day long', 'a', 'John 15:13 — "Greater love hath no man than this, that a man lay down his life for his friends."'),
-- Teens
('John', 15, 'teens', 1, 'In the vine and branches metaphor, who is the farmer (husbandman)?', 'The Father', 'Jesus', 'The Holy Spirit', 'The disciples', 'a', 'John 15:1 — "I am the true vine, and my Father is the husbandman."'),
('John', 15, 'teens', 2, 'What happens to branches that do not bear fruit?', 'They are taken away; branches that bear fruit are pruned to bear more', 'They are watered more until they produce', 'They are replanted in better soil', 'They are left alone to grow naturally', 'a', 'John 15:2 — "Every branch in me that beareth not fruit he taketh away: and every branch that beareth fruit, he purgeth it, that it may bring forth more fruit."'),
('John', 15, 'teens', 3, 'What did Jesus say about doing things without Him?', '"Without me ye can do nothing"', '"Without me ye will struggle but still succeed"', '"Without me ye must rely on the law"', '"Without me ye must find another teacher"', 'a', 'John 15:5 — "without me ye can do nothing."'),
('John', 15, 'teens', 4, 'What did Jesus call His disciples instead of servants?', 'Friends — "I have called you friends"', 'Brothers — "I have called you brothers"', 'Sons — "I have called you sons"', 'Chosen ones — "I have called you chosen"', 'a', 'John 15:15 — "I have called you friends."'),
('John', 15, 'teens', 5, 'Why did Jesus say the world would hate His disciples?', 'Because they are not of the world, just as Jesus is not of the world', 'Because they would perform miracles the world envied', 'Because they would become wealthy and powerful', 'Because they would refuse to pay Roman taxes', 'a', 'John 15:19 — "because ye are not of the world, but I have chosen you out of the world, therefore the world hateth you."'),
-- Adults
('John', 15, 'adults', 1, 'What condition does Jesus give for effective prayer in the vine discourse?', '"If ye abide in me, and my words abide in you, ye shall ask what ye will, and it shall be done unto you"', '"If ye fast and pray continually, your requests will be granted"', '"If ye keep all the commandments, the Father will hear you"', '"If ye pray in the temple, your prayers will be answered"', 'a', 'John 15:7 — "If ye abide in me, and my words abide in you, ye shall ask what ye will, and it shall be done unto you."'),
('John', 15, 'adults', 2, 'What does Jesus say is the evidence that proves we are His disciples?', '"Herein is my Father glorified, that ye bear much fruit; so shall ye be my disciples"', '"By your knowledge of the Scriptures, men will know you are mine"', '"By your miracles, men will know the Father sent me"', '"By your obedience to every commandment"', 'a', 'John 15:8 — "Herein is my Father glorified, that ye bear much fruit; so shall ye be my disciples."'),
('John', 15, 'adults', 3, 'Why did Jesus say He no longer calls His disciples servants?', '"The servant knoweth not what his lord doeth: but I have called you friends; for all things that I have heard of my Father I have made known unto you"', '"Because you have earned the title of friend through your loyalty"', '"Because servants cannot enter the kingdom of heaven"', '"Because the servant''s role has ended now that the Messiah has come"', 'a', 'John 15:15 — "the servant knoweth not what his lord doeth: but I have called you friends; for all things that I have heard of my Father I have made known unto you."'),
('John', 15, 'adults', 4, 'What principle did Jesus state about the relationship between hatred toward Him and hatred toward the Father?', '"He that hateth me hateth my Father also"', '"Those who hate me will eventually come to love the Father"', '"Hatred of me does not affect one''s standing before the Father"', '"The Father will judge those who hate me at the last day"', 'a', 'John 15:23 — "He that hateth me hateth my Father also."'),
('John', 15, 'adults', 5, 'What does Jesus say about the guilt of those who have seen His works?', '"If I had not done among them the works which none other man did, they had not had sin: but now have they both seen and hated both me and my Father"', '"Their guilt is lessened because they did not understand"', '"They will be forgiven because they acted in ignorance"', '"Their sin would be the same whether or not they saw the works"', 'a', 'John 15:24 — "If I had not done among them the works which none other man did, they had not had sin."'),
('John', 15, 'adults', 6, 'What Old Testament Scripture does Jesus say is fulfilled by the hatred against Him?', '"They hated me without a cause" (Psalm 35:19 / Psalm 69:4)', '"The stone which the builders rejected" (Psalm 118:22)', '"He was despised and rejected of men" (Isaiah 53:3)', '"They pierced my hands and my feet" (Psalm 22:16)', 'a', 'John 15:25 — "But this cometh to pass, that the word might be fulfilled that is written in their law, They hated me without a cause."'),
('John', 15, 'adults', 7, 'What does Jesus say the Comforter will do when He comes?', '"He shall testify of me" — and the disciples shall also bear witness', '"He shall judge the world and convict sinners"', '"He shall establish the church in Jerusalem"', '"He shall write new scriptures for the people"', 'a', 'John 15:26-27 — "he shall testify of me: And ye also shall bear witness."'),
('John', 15, 'adults', 8, 'What is the commandment Jesus specifically ties to the vine metaphor about love?', '"This is my commandment, That ye love one another, as I have loved you"', '"Love the Lord thy God with all thy heart"', '"Love thy neighbour as thyself"', '"Love your enemies and pray for those who persecute you"', 'a', 'John 15:12 — "This is my commandment, That ye love one another, as I have loved you."');

-- ═══════════════════════════════════════════════════════════════════════════
-- CHAPTERS 16 – 21
-- ═══════════════════════════════════════════════════════════════════════════

-- ═══ John Chapter 16 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('John', 16, 'kids', 1, 'Who did Jesus promise to send after He went away?', 'The Comforter (Holy Spirit)', 'An army of angels', 'A new king', 'His mother Mary', 'a', 'John 16:7 — "if I depart, I will send him [the Comforter] unto you."'),
('John', 16, 'kids', 2, 'What did Jesus say about sadness turning into something else?', 'Sorrow would be turned into joy', 'Sorrow would be turned into sleep', 'Sorrow would be turned into work', 'Sorrow would be turned into silence', 'a', 'John 16:20 — "your sorrow shall be turned into joy."'),
('John', 16, 'kids', 3, 'What did Jesus say He had done to the world to encourage His disciples?', '"Be of good cheer; I have overcome the world"', '"Be of good cheer; I have rebuilt the world"', '"Be of good cheer; I have hidden from the world"', '"Be of good cheer; I have escaped the world"', 'a', 'John 16:33 — "be of good cheer; I have overcome the world."'),
-- Teens
('John', 16, 'teens', 1, 'What three things did Jesus say the Spirit of truth would convict the world of?', 'Sin, righteousness, and judgment', 'Greed, pride, and hatred', 'Lying, stealing, and murder', 'Unbelief, idolatry, and blasphemy', 'a', 'John 16:8 — "he will reprove the world of sin, and of righteousness, and of judgment."'),
('John', 16, 'teens', 2, 'What did Jesus say the Spirit of truth would do when He came?', '"He will guide you into all truth" and show things to come', 'He would give them power to defeat Rome', 'He would make them invisible to their enemies', 'He would write new laws for them to follow', 'a', 'John 16:13 — "when he, the Spirit of truth, is come, he will guide you into all truth… and he will shew you things to come."'),
('John', 16, 'teens', 3, 'What comparison did Jesus use for the disciples'' sorrow and joy?', 'A woman in labor — she has sorrow during childbirth but joy when the child is born', 'A farmer waiting for harvest — sorrow in planting, joy in reaping', 'A student studying — sorrow in learning, joy in passing the test', 'A soldier in battle — sorrow in fighting, joy in victory', 'a', 'John 16:21 — "A woman when she is in travail hath sorrow… but as soon as she is delivered of the child, she remembereth no more the anguish, for joy."'),
('John', 16, 'teens', 4, 'What phrase did Jesus keep using about a short time?', '"A little while, and ye shall not see me: and again, a little while, and ye shall see me"', '"For a moment I leave, but I will return forever"', '"In a short season the kingdom will come"', '"Before the sun sets twice, I will appear again"', 'a', 'John 16:16 — "A little while, and ye shall not see me: and again, a little while, and ye shall see me."'),
('John', 16, 'teens', 5, 'What warning did Jesus give about what would happen to His followers?', 'They would be put out of the synagogues, and some would be killed by those who thought they were serving God', 'They would be imprisoned by the Romans', 'They would lose all their money and possessions', 'They would be scattered to foreign lands', 'a', 'John 16:2 — "They shall put you out of the synagogues: yea, the time cometh, that whosoever killeth you will think that he doeth God service."'),
-- Adults
('John', 16, 'adults', 1, 'Why did Jesus say it was "expedient" (advantageous) for Him to go away?', '"If I go not away, the Comforter will not come unto you; but if I depart, I will send him unto you"', '"So that you will learn to stand on your own faith"', '"Because the Father requires me to return before sending help"', '"So that the world will no longer persecute you through me"', 'a', 'John 16:7 — "if I go not away, the Comforter will not come unto you; but if I depart, I will send him unto you."'),
('John', 16, 'adults', 2, 'How does Jesus explain the Spirit''s conviction concerning sin?', '"Of sin, because they believe not on me"', '"Of sin, because they have broken the law"', '"Of sin, because they have rejected the prophets"', '"Of sin, because they worship false gods"', 'a', 'John 16:9 — "Of sin, because they believe not on me."'),
('John', 16, 'adults', 3, 'How does Jesus explain the Spirit''s conviction concerning righteousness?', '"Of righteousness, because I go to my Father, and ye see me no more"', '"Of righteousness, because the law demands perfection"', '"Of righteousness, because God is holy"', '"Of righteousness, because the prophets spoke of justice"', 'a', 'John 16:10 — "Of righteousness, because I go to my Father, and ye see me no more."'),
('John', 16, 'adults', 4, 'How does Jesus explain the Spirit''s conviction concerning judgment?', '"Of judgment, because the prince of this world is judged"', '"Of judgment, because the day of the Lord is near"', '"Of judgment, because all must appear before God''s throne"', '"Of judgment, because the wicked will be destroyed"', 'a', 'John 16:11 — "Of judgment, because the prince of this world is judged."'),
('John', 16, 'adults', 5, 'What does Jesus say about the Spirit''s source of teaching?', '"He shall not speak of himself; but whatsoever he shall hear, that shall he speak"', '"He shall bring new revelation unknown to the prophets"', '"He shall speak only what the disciples ask Him"', '"He shall interpret the law of Moses in a new way"', 'a', 'John 16:13 — "he shall not speak of himself; but whatsoever he shall hear, that shall he speak."'),
('John', 16, 'adults', 6, 'What does Jesus say the Spirit will do regarding Jesus Himself?', '"He shall glorify me: for he shall receive of mine, and shall shew it unto you"', '"He shall establish my kingdom on earth in my absence"', '"He shall remind you of Moses and the prophets"', '"He shall give you power to continue my miracles"', 'a', 'John 16:14 — "He shall glorify me: for he shall receive of mine, and shall shew it unto you."'),
('John', 16, 'adults', 7, 'What promise about prayer does Jesus make in John 16:23-24?', '"Whatsoever ye shall ask the Father in my name, he will give it you… ask, and ye shall receive, that your joy may be full"', '"Pray without ceasing and the Father will hear every word"', '"If two or three agree, it shall be done"', '"Whatever you bind on earth shall be bound in heaven"', 'a', 'John 16:23-24 — "Whatsoever ye shall ask the Father in my name, he will give it you… ask, and ye shall receive, that your joy may be full."'),
('John', 16, 'adults', 8, 'What did the disciples finally say they now understood about Jesus?', '"Now are we sure that thou knowest all things… by this we believe that thou camest forth from God"', '"We now understand all your parables and teachings"', '"We believe you are the prophet Moses foretold"', '"We know you will defeat Rome and restore Israel"', 'a', 'John 16:30 — "Now are we sure that thou knowest all things… by this we believe that thou camest forth from God."'),

-- ═══ John Chapter 17 ═══
-- Kids
('John', 17, 'kids', 1, 'What did Jesus do for His disciples in this whole chapter?', 'He prayed for them', 'He taught them a new song', 'He fed them bread and fish', 'He healed their sicknesses', 'a', 'John 17 is Jesus'' prayer for His disciples (the High Priestly Prayer).'),
('John', 17, 'kids', 2, 'What did Jesus ask the Father to do for His followers?', 'Keep them safe and make them one (united)', 'Make them rich and famous', 'Give them a big house', 'Send them on a long vacation', 'a', 'John 17:11 — "Holy Father, keep through thine own name those whom thou hast given me, that they may be one."'),
('John', 17, 'kids', 3, 'Did Jesus pray only for His disciples, or for others too?', 'He also prayed for all future believers', 'He prayed only for the twelve disciples', 'He prayed only for the people of Israel', 'He prayed only for Himself', 'a', 'John 17:20 — "Neither pray I for these alone, but for them also which shall believe on me through their word."'),
-- Teens
('John', 17, 'teens', 1, 'How did Jesus define eternal life in His prayer?', '"That they might know thee the only true God, and Jesus Christ, whom thou hast sent"', '"That they might live forever in a perfect world"', '"That they might have everlasting health and wealth"', '"That they might keep all the commandments perfectly"', 'a', 'John 17:3 — "this is life eternal, that they might know thee the only true God, and Jesus Christ, whom thou hast sent."'),
('John', 17, 'teens', 2, 'What did Jesus say He had given to His disciples from the Father?', 'The Father''s words — and they received them and believed', 'The Father''s crown and kingdom', 'The Father''s written law', 'The Father''s heavenly throne', 'a', 'John 17:8 — "I have given unto them the words which thou gavest me; and they have received them."'),
('John', 17, 'teens', 3, 'What did Jesus ask the Father to protect His disciples from?', 'The evil one (the devil)', 'The Roman soldiers', 'Physical sickness and death', 'Poverty and hunger', 'a', 'John 17:15 — "I pray not that thou shouldest take them out of the world, but that thou shouldest keep them from the evil."'),
('John', 17, 'teens', 4, 'What did Jesus ask the Father to do for believers through His truth?', '"Sanctify them through thy truth: thy word is truth"', '"Teach them new commandments"', '"Give them power over their enemies"', '"Translate them into heaven immediately"', 'a', 'John 17:17 — "Sanctify them through thy truth: thy word is truth."'),
('John', 17, 'teens', 5, 'What was Jesus'' desire for all believers to see?', 'His glory which the Father gave Him before the foundation of the world', 'The new Jerusalem coming down from heaven', 'The angels worshipping around God''s throne', 'The destruction of all evil in the world', 'a', 'John 17:24 — "I will that they also, whom thou hast given me, be with me where I am; that they may behold my glory, which thou hast given me: for thou lovedst me before the foundation of the world."'),
-- Adults
('John', 17, 'adults', 1, 'What does Jesus claim He has done with the Father''s name?', '"I have manifested thy name unto the men which thou gavest me out of the world"', '"I have written thy name upon their hearts"', '"I have proclaimed thy name in the temple"', '"I have revealed thy name to all the nations"', 'a', 'John 17:6 — "I have manifested thy name unto the men which thou gavest me out of the world."'),
('John', 17, 'adults', 2, 'What does Jesus say about the one who was lost among the twelve?', '"None of them is lost, but the son of perdition; that the scripture might be fulfilled"', '"One was taken by the enemy against my will"', '"One chose the path of destruction despite many warnings"', '"One fell away because his faith was weak"', 'a', 'John 17:12 — "none of them is lost, but the son of perdition; that the scripture might be fulfilled."'),
('John', 17, 'adults', 3, 'What does Jesus pray regarding the unity of believers?', '"That they all may be one; as thou, Father, art in me, and I in thee, that they also may be one in us"', '"That they may agree on all matters of doctrine"', '"That they may form one visible organization"', '"That they may never argue or disagree"', 'a', 'John 17:21 — "That they all may be one; as thou, Father, art in me, and I in thee, that they also may be one in us."'),
('John', 17, 'adults', 4, 'What glory does Jesus say He shared with the disciples?', '"The glory which thou gavest me I have given them; that they may be one, even as we are one"', '"The glory of performing miracles in my name"', '"The glory of ruling over the nations"', '"The glory of being called sons of God"', 'a', 'John 17:22 — "the glory which thou gavest me I have given them; that they may be one, even as we are one."'),
('John', 17, 'adults', 5, 'What does Jesus claim about the world''s knowledge of the Father?', '"O righteous Father, the world hath not known thee: but I have known thee, and these have known that thou hast sent me"', '"The world knows thee through creation but rejects thy Son"', '"The world worships thee but does not understand thy ways"', '"The world will come to know thee through the testimony of the disciples"', 'a', 'John 17:25 — "O righteous Father, the world hath not known thee: but I have known thee, and these have known that thou hast sent me."'),
('John', 17, 'adults', 6, 'What was Jesus'' stated purpose for being sent into the world regarding the disciples?', '"As thou hast sent me into the world, even so have I also sent them into the world"', '"I came to gather them from every nation"', '"I came to establish a new priesthood among them"', '"I came to teach them the mysteries of the kingdom"', 'a', 'John 17:18 — "As thou hast sent me into the world, even so have I also sent them into the world."'),
('John', 17, 'adults', 7, 'What does Jesus say He does for the disciples'' sake regarding sanctification?', '"For their sakes I sanctify myself, that they also might be sanctified through the truth"', '"I have given them the law so they can purify themselves"', '"I have appointed priests to sanctify them on my behalf"', '"I have set them apart by removing them from the world"', 'a', 'John 17:19 — "for their sakes I sanctify myself, that they also might be sanctified through the truth."'),
('John', 17, 'adults', 8, 'What is the ultimate purpose of believers'' unity, according to Jesus'' prayer?', '"That the world may believe that thou hast sent me" and "that the world may know that thou hast sent me"', '"That the church may be strong against persecution"', '"That disputes among believers may cease"', '"That the gospel may be preached more effectively"', 'a', 'John 17:21,23 — "that the world may believe that thou hast sent me" and "that the world may know that thou hast sent me."'),

-- ═══ John Chapter 18 ═══
-- Kids
('John', 18, 'kids', 1, 'Who betrayed Jesus and brought soldiers to arrest Him?', 'Judas', 'Peter', 'Thomas', 'Andrew', 'a', 'John 18:2-3 — "Judas… having received a band of men and officers… cometh thither."'),
('John', 18, 'kids', 2, 'What did Peter do when the soldiers came to arrest Jesus?', 'He cut off a servant''s ear with a sword', 'He ran away and hid', 'He called down fire from heaven', 'He stood still and prayed', 'a', 'John 18:10 — "Simon Peter having a sword drew it, and smote the high priest''s servant, and cut off his right ear."'),
('John', 18, 'kids', 3, 'How many times did Peter say he did not know Jesus?', 'Three times', 'Two times', 'One time', 'Four times', 'a', 'John 18:17,25,27 — Peter denied Jesus three times.'),
-- Teens
('John', 18, 'teens', 1, 'What happened when Jesus said "I am he" to the soldiers who came to arrest Him?', 'They went backward and fell to the ground', 'They dropped their weapons', 'They ran away in fear', 'They bowed down and worshipped', 'a', 'John 18:6 — "As soon then as he had said unto them, I am he, they went backward, and fell to the ground."'),
('John', 18, 'teens', 2, 'What was the name of the servant whose ear Peter cut off?', 'Malchus', 'Marcus', 'Lazarus', 'Barabbas', 'a', 'John 18:10 — "The servant''s name was Malchus."'),
('John', 18, 'teens', 3, 'What did Jesus say to Peter about the sword?', '"Put up thy sword into the sheath: the cup which my Father hath given me, shall I not drink it?"', '"Those who live by the sword will die by the sword"', '"I have no need of your protection"', '"Do not fight, for my kingdom is not of this world"', 'a', 'John 18:11 — "Put up thy sword into the sheath: the cup which my Father hath given me, shall I not drink it?"'),
('John', 18, 'teens', 4, 'Who was Jesus taken to first after His arrest?', 'Annas, the father-in-law of the high priest Caiaphas', 'Pontius Pilate the Roman governor', 'King Herod', 'The Sanhedrin council', 'a', 'John 18:13 — "led him away to Annas first; for he was father in law to Caiaphas."'),
('John', 18, 'teens', 5, 'What did Pilate ask Jesus that received a famous answer about His kingdom?', '"Art thou the King of the Jews?" — Jesus said His kingdom is not of this world', '"Are you the Son of God?"', '"Have you broken the law of Moses?"', '"Do you claim to be greater than Caesar?"', 'a', 'John 18:33,36 — "Art thou the King of the Jews?… My kingdom is not of this world."'),
-- Adults
('John', 18, 'adults', 1, 'What is the name of the garden where Jesus was arrested?', 'A garden across the brook Cedron (Kidron) — traditionally Gethsemane', 'The Garden of Eden', 'The garden near the Pool of Siloam', 'The king''s garden near the walls of Jerusalem', 'a', 'John 18:1 — "he went forth with his disciples over the brook Cedron, where was a garden."'),
('John', 18, 'adults', 2, 'What did Jesus request for His disciples at the moment of arrest?', '"If therefore ye seek me, let these go their way" — fulfilling His word that He lost none given to Him', '"Protect my disciples from the soldiers"', '"Let them return to their homes in peace"', '"Do not punish them for my sake"', 'a', 'John 18:8-9 — "If therefore ye seek me, let these go their way: That the saying might be fulfilled, which he spake, Of them which thou gavest me have I lost none."'),
('John', 18, 'adults', 3, 'Which disciple followed Jesus into the high priest''s palace because he was known to the high priest?', 'Another disciple (traditionally identified as John) who was known to the high priest and brought Peter in', 'Nicodemus who was a Pharisee', 'Joseph of Arimathaea', 'Matthew the tax collector', 'a', 'John 18:15-16 — "that other disciple was known unto the high priest, and went in… and brought in Peter."'),
('John', 18, 'adults', 4, 'What did Jesus say when an officer struck Him for His answer to the high priest?', '"If I have spoken evil, bear witness of the evil: but if well, why smitest thou me?"', '"Father, forgive him, for he knows not what he does"', '"You have no right to strike the Son of God"', '"The Father will judge you for this"', 'a', 'John 18:23 — "If I have spoken evil, bear witness of the evil: but if well, why smitest thou me?"'),
('John', 18, 'adults', 5, 'What did Jesus tell Pilate about the nature of His kingdom?', '"My kingdom is not of this world: if my kingdom were of this world, then would my servants fight"', '"My kingdom shall overthrow all earthly kingdoms"', '"My kingdom is spiritual and has no earthly manifestation"', '"My kingdom will come after the Romans fall"', 'a', 'John 18:36 — "My kingdom is not of this world: if my kingdom were of this world, then would my servants fight."'),
('John', 18, 'adults', 6, 'What was Pilate''s famous philosophical question to Jesus?', '"What is truth?"', '"What is justice?"', '"What is power?"', '"What is freedom?"', 'a', 'John 18:38 — "Pilate saith unto him, What is truth?"'),
('John', 18, 'adults', 7, 'Whom did the Jews choose to be released instead of Jesus?', 'Barabbas, who was a robber', 'A murderer named Simon', 'A zealot named Judas', 'A thief named Dysmas', 'a', 'John 18:40 — "Not this man, but Barabbas. Now Barabbas was a robber."'),
('John', 18, 'adults', 8, 'What detail does John give about Peter''s third denial?', 'A relative of Malchus (whose ear Peter had cut off) asked "Did not I see thee in the garden with him?" — and the cock crew immediately', 'A servant girl recognized Peter by his Galilean accent', 'The soldiers identified Peter by his sword', 'The high priest himself questioned Peter directly', 'a', 'John 18:26-27 — "One of the servants of the high priest, being his kinsman whose ear Peter cut off, saith, Did not I see thee in the garden with him? Peter then denied again: and immediately the cock crew."'),

-- ═══ John Chapter 19 ═══
-- Kids
('John', 19, 'kids', 1, 'What was put on Jesus'' head to hurt and mock Him?', 'A crown of thorns', 'A crown of gold', 'A helmet of iron', 'A wreath of flowers', 'a', 'John 19:2 — "the soldiers platted a crown of thorns, and put it on his head."'),
('John', 19, 'kids', 2, 'What did Jesus say just before He died on the cross?', '"It is finished"', '"I will return"', '"Forgive them all"', '"Remember me"', 'a', 'John 19:30 — "he said, It is finished: and he bowed his head, and gave up the ghost."'),
('John', 19, 'kids', 3, 'Where was Jesus crucified?', 'A place called Golgotha (the place of a skull)', 'On the Mount of Olives', 'In the temple courts', 'At the pool of Bethesda', 'a', 'John 19:17 — "a place called the place of a skull, which is called in the Hebrew Golgotha."'),
-- Teens
('John', 19, 'teens', 1, 'What words did Pilate say when he presented Jesus to the crowd?', '"Behold the man!"', '"Here is your king!"', '"See the prisoner!"', '"Judge for yourselves!"', 'a', 'John 19:5 — "Pilate saith unto them, Behold the man!"'),
('John', 19, 'teens', 2, 'What was written on the sign (title) placed on Jesus'' cross?', '"JESUS OF NAZARETH THE KING OF THE JEWS" in Hebrew, Greek, and Latin', '"This man claimed to be the Son of God"', '"The Messiah of Israel"', '"King of all the earth"', 'a', 'John 19:19-20 — "JESUS OF NAZARETH THE KING OF THE JEWS… in Hebrew, and Greek, and Latin."'),
('John', 19, 'teens', 3, 'What did the soldiers do with Jesus'' coat?', 'They cast lots for it because it was woven without a seam', 'They tore it into four pieces', 'They gave it to His mother', 'They burned it as an offering', 'a', 'John 19:23-24 — "the coat was without seam, woven from the top throughout… Let us not rend it, but cast lots."'),
('John', 19, 'teens', 4, 'What came out of Jesus'' side when a soldier pierced it with a spear?', 'Blood and water', 'Only blood', 'Only water', 'Nothing', 'a', 'John 19:34 — "one of the soldiers with a spear pierced his side, and forthwith came there out blood and water."'),
('John', 19, 'teens', 5, 'Who buried Jesus'' body?', 'Joseph of Arimathaea and Nicodemus', 'Peter and John', 'Mary Magdalene and Mary His mother', 'The Roman soldiers', 'a', 'John 19:38-39 — "Joseph of Arimathaea… and… Nicodemus."'),
-- Adults
('John', 19, 'adults', 1, 'What did Pilate say to Jesus about his authority, and how did Jesus respond?', 'Pilate said he had power to crucify or release; Jesus said "Thou couldest have no power at all against me, except it were given thee from above"', 'Pilate claimed Caesar''s authority; Jesus said all authority is God''s', 'Pilate said Rome rules all; Jesus said the Father rules above Rome', 'Pilate boasted of his rank; Jesus reminded him of his mortality', 'a', 'John 19:10-11 — "Thou couldest have no power at all against me, except it were given thee from above."'),
('John', 19, 'adults', 2, 'What argument did the Jews use to pressure Pilate into crucifying Jesus?', '"If thou let this man go, thou art not Caesar''s friend: whosoever maketh himself a king speaketh against Caesar"', '"Our law says He must die for blasphemy"', '"He has incited rebellion against Rome"', '"The people will riot if you release Him"', 'a', 'John 19:12 — "If thou let this man go, thou art not Caesar''s friend."'),
('John', 19, 'adults', 3, 'What did the chief priests say when Pilate asked "Shall I crucify your King?"', '"We have no king but Caesar"', '"He is not our king"', '"Crucify Him and give us Barabbas"', '"We reject this blasphemer"', 'a', 'John 19:15 — "The chief priests answered, We have no king but Caesar."'),
('John', 19, 'adults', 4, 'What did Jesus say to His mother and the beloved disciple from the cross?', 'To His mother: "Woman, behold thy son!" To the disciple: "Behold thy mother!" — and the disciple took her to his own home', '"Take care of one another"', '"Remember me when I am gone"', '"Go to Galilee and wait for me"', 'a', 'John 19:26-27 — "Woman, behold thy son!… Behold thy mother! And from that hour that disciple took her unto his own home."'),
('John', 19, 'adults', 5, 'What Old Testament Scripture was fulfilled by the soldiers not breaking Jesus'' bones?', '"A bone of him shall not be broken" (Exodus 12:46 / Psalm 34:20)', '"He keepeth all his bones: not one of them is broken" (Psalm 34:20)', '"They shall look on him whom they pierced" (Zechariah 12:10)', '"He was wounded for our transgressions" (Isaiah 53:5)', 'a', 'John 19:36 — "A bone of him shall not be broken."'),
('John', 19, 'adults', 6, 'What prophecy was fulfilled by the piercing of Jesus'' side?', '"They shall look on him whom they pierced" (Zechariah 12:10)', '"A bone of him shall not be broken"', '"He was numbered with the transgressors" (Isaiah 53:12)', '"They parted my garments among them" (Psalm 22:18)', 'a', 'John 19:37 — "And again another scripture saith, They shall look on him whom they pierced."'),
('John', 19, 'adults', 7, 'How much spice did Nicodemus bring for Jesus'' burial?', 'A mixture of myrrh and aloes, about an hundred pound weight', 'Frankincense and myrrh, about fifty pounds', 'Pure nard and spices, about thirty pounds', 'Aloes and cassia, about seventy pounds', 'a', 'John 19:39 — "Nicodemus… brought a mixture of myrrh and aloes, about an hundred pound weight."'),
('John', 19, 'adults', 8, 'What was Jesus'' response when He knew all things were accomplished before He died?', 'He said "I thirst" — and after receiving vinegar on hyssop, He said "It is finished"', 'He cried out "My God, my God, why hast thou forsaken me?"', 'He prayed silently and bowed His head', 'He called out to His mother and then died', 'a', 'John 19:28-30 — Jesus said "I thirst"… "It is finished: and he bowed his head, and gave up the ghost."'),

-- ═══ John Chapter 20 ═══
-- Kids
('John', 20, 'kids', 1, 'Who came to Jesus'' tomb early in the morning and found it empty?', 'Mary Magdalene', 'Peter', 'John', 'Martha', 'a', 'John 20:1 — "Mary Magdalene… cometh… unto the sepulchre, and seeth the stone taken away."'),
('John', 20, 'kids', 2, 'Which disciple did not believe Jesus was alive until he saw Him?', 'Thomas', 'Peter', 'Andrew', 'Philip', 'a', 'John 20:25 — Thomas said he would not believe unless he saw and touched Jesus'' wounds.'),
('John', 20, 'kids', 3, 'What did Jesus show His disciples to prove it was really Him?', 'His hands and His side (where He was wounded)', 'A bright shining light', 'A scroll with His name', 'A special ring', 'a', 'John 20:20 — "he shewed unto them his hands and his side."'),
-- Teens
('John', 20, 'teens', 1, 'What did Mary Magdalene first think had happened to Jesus'' body?', 'Someone had taken the Lord out of the sepulchre', 'He had risen as He predicted', 'The soldiers had moved Him to another tomb', 'The Pharisees had stolen His body', 'a', 'John 20:2 — "They have taken away the Lord out of the sepulchre, and we know not where they have laid him."'),
('John', 20, 'teens', 2, 'Who reached the tomb first — Peter or the other disciple?', 'The other disciple outran Peter and reached the tomb first', 'Peter reached the tomb first', 'They arrived at the same time', 'Neither went to the tomb', 'a', 'John 20:4 — "the other disciple did outrun Peter, and came first to the sepulchre."'),
('John', 20, 'teens', 3, 'What did Jesus say to Mary Magdalene when she recognized Him?', '"Touch me not; for I am not yet ascended to my Father"', '"Go and tell my disciples I am alive"', '"Do not be afraid; it is I"', '"Follow me to Galilee"', 'a', 'John 20:17 — "Touch me not; for I am not yet ascended to my Father."'),
('John', 20, 'teens', 4, 'What did Jesus breathe on the disciples and say?', '"Receive ye the Holy Ghost"', '"Peace be unto you"', '"Be filled with power"', '"Go into all the world"', 'a', 'John 20:22 — "he breathed on them, and saith unto them, Receive ye the Holy Ghost."'),
('John', 20, 'teens', 5, 'What did Thomas say when he finally saw Jesus?', '"My Lord and my God"', '"I believe; help my unbelief"', '"Truly you are the Son of God"', '"Master, forgive my doubts"', 'a', 'John 20:28 — "Thomas answered and said unto him, My Lord and my God."'),
-- Adults
('John', 20, 'adults', 1, 'What specific detail about the grave clothes did Peter see when he entered the tomb?', 'The linen clothes were lying there, and the napkin that was about His head was wrapped together in a place by itself', 'The clothes were scattered on the floor', 'The clothes were folded neatly in a pile together', 'The clothes were hanging on the wall of the tomb', 'a', 'John 20:6-7 — "seeth the linen clothes lie, And the napkin, that was about his head, not lying with the linen clothes, but wrapped together in a place by itself."'),
('John', 20, 'adults', 2, 'What did Mary Magdalene see inside the tomb?', 'Two angels in white sitting where the body of Jesus had lain, one at the head and one at the feet', 'A single angel standing at the entrance', 'A bright light filling the empty space', 'Three men in shining garments', 'a', 'John 20:12 — "seeth two angels in white sitting, the one at the head, and the other at the feet, where the body of Jesus had lain."'),
('John', 20, 'adults', 3, 'Who did Mary Magdalene initially think the risen Jesus was?', 'The gardener', 'An angel', 'A Roman soldier', 'One of the disciples', 'a', 'John 20:15 — "She, supposing him to be the gardener."'),
('John', 20, 'adults', 4, 'What words did Jesus say that caused Mary to recognize Him?', 'He said her name: "Mary"', 'He quoted a passage of Scripture', 'He showed her His hands', 'He reminded her of a past miracle', 'a', 'John 20:16 — "Jesus saith unto her, Mary. She turned herself, and saith unto him, Rabboni."'),
('John', 20, 'adults', 5, 'What authority did Jesus give the disciples regarding sins?', '"Whose soever sins ye remit, they are remitted unto them; and whose soever sins ye retain, they are retained"', '"You have authority to forgive all sins in my name"', '"Preach repentance and the forgiveness of sins"', '"Pray for sinners and I will hear your prayers"', 'a', 'John 20:23 — "Whose soever sins ye remit, they are remitted unto them; and whose soever sins ye retain, they are retained."'),
('John', 20, 'adults', 6, 'What specific proof did Thomas demand before he would believe?', '"Except I shall see in his hands the print of the nails, and put my finger into the print of the nails, and thrust my hand into his side, I will not believe"', '"Unless He appears to me alone and speaks my name"', '"Unless He performs a miracle before my eyes"', '"Unless Peter and John both testify under oath"', 'a', 'John 20:25 — "Except I shall see in his hands the print of the nails, and put my finger into the print of the nails, and thrust my hand into his side, I will not believe."'),
('John', 20, 'adults', 7, 'What did Jesus say to Thomas after Thomas believed?', '"Thomas, because thou hast seen me, thou hast believed: blessed are they that have not seen, and yet have believed"', '"Your faith has made you whole"', '"Go and tell the others what you have seen"', '"Do not doubt again, but always believe"', 'a', 'John 20:29 — "Thomas, because thou hast seen me, thou hast believed: blessed are they that have not seen, and yet have believed."'),
('John', 20, 'adults', 8, 'What does John state as the purpose of writing his Gospel?', '"These are written, that ye might believe that Jesus is the Christ, the Son of God; and that believing ye might have life through his name"', '"These are written as a historical record for future generations"', '"These are written so that the church may have authority"', '"These are written to fulfill the words of the prophets"', 'a', 'John 20:31 — "these are written, that ye might believe that Jesus is the Christ, the Son of God; and that believing ye might have life through his name."'),

-- ═══ John Chapter 21 ═══
-- Kids
('John', 21, 'kids', 1, 'How many fish did the disciples catch when Jesus told them to cast the net on the right side?', 'One hundred and fifty-three', 'Twelve', 'Fifty', 'One thousand', 'a', 'John 21:11 — "an hundred and fifty and three" great fishes.'),
('John', 21, 'kids', 2, 'What question did Jesus ask Peter three times?', '"Lovest thou me?"', '"Will you follow me?"', '"Do you believe in me?"', '"Are you my friend?"', 'a', 'John 21:15-17 — Jesus asked Peter three times if he loved Him.'),
('John', 21, 'kids', 3, 'What did Jesus tell Peter to do after Peter said he loved Him?', '"Feed my sheep" (and "Feed my lambs")', '"Build me a temple"', '"Write a book about me"', '"Travel to a far country"', 'a', 'John 21:15-17 — Jesus said "Feed my lambs," "Feed my sheep," and "Feed my sheep."'),
-- Teens
('John', 21, 'teens', 1, 'Where did Jesus appear to the disciples in this chapter?', 'At the Sea of Tiberias (Sea of Galilee)', 'In the upper room in Jerusalem', 'On the Mount of Olives', 'At the temple in Jerusalem', 'a', 'John 21:1 — "Jesus shewed himself again to the disciples at the sea of Tiberias."'),
('John', 21, 'teens', 2, 'What had the disciples been doing all night before Jesus appeared?', 'Fishing — but they had caught nothing', 'Praying in a house nearby', 'Walking along the shore', 'Sleeping in a boat', 'a', 'John 21:3 — "They went forth, and entered into a ship immediately; and that night they caught nothing."'),
('John', 21, 'teens', 3, 'Which disciple jumped into the sea to swim to Jesus when he recognized Him?', 'Peter', 'John', 'Thomas', 'Andrew', 'a', 'John 21:7 — "Simon Peter… did cast himself into the sea."'),
('John', 21, 'teens', 4, 'Why do scholars think Jesus asked Peter "Lovest thou me?" three times?', 'To restore Peter after his three denials', 'Because Peter was hard of hearing', 'To make sure the other disciples heard', 'Because it was a Jewish legal custom', 'a', 'John 21:15-17 — The three questions correspond to Peter''s three denials in John 18.'),
('John', 21, 'teens', 5, 'What did Jesus say about how Peter would die?', 'He would stretch forth his hands and be carried where he did not wish to go (signifying crucifixion)', 'He would die peacefully in old age', 'He would be stoned for preaching', 'He would drown at sea', 'a', 'John 21:18-19 — "thou shalt stretch forth thy hands, and another shall gird thee, and carry thee whither thou wouldest not. This spake he, signifying by what death he should glorify God."'),
-- Adults
('John', 21, 'adults', 1, 'What was already prepared on shore when the disciples arrived with the fish?', 'A fire of coals with fish laid on it and bread', 'A feast prepared by angels', 'A table set with cups and wine', 'A tent with provisions inside', 'a', 'John 21:9 — "they saw a fire of coals there, and fish laid thereon, and bread."'),
('John', 21, 'adults', 2, 'Despite the great number of fish (153), what was notable about the net?', 'It was not broken', 'It was torn in many places', 'It sank under the weight', 'It had to be dragged by two boats', 'a', 'John 21:11 — "drew the net to land full of great fishes, an hundred and fifty and three: and for all there were so many, yet was not the net broken."'),
('John', 21, 'adults', 3, 'Which disciple first recognized that the figure on shore was Jesus?', 'The disciple whom Jesus loved (John) said "It is the Lord"', 'Peter recognized Him immediately', 'Thomas pointed Him out', 'Andrew said "It is the Master"', 'a', 'John 21:7 — "Therefore that disciple whom Jesus loved saith unto Peter, It is the Lord."'),
('John', 21, 'adults', 4, 'What distinction in Greek words for "love" is significant in the exchange between Jesus and Peter?', 'Jesus first used "agapao" (selfless love); Peter responded with "phileo" (affection). The third time Jesus switched to "phileo"', 'Jesus used "phileo" all three times and Peter used "agapao"', 'Both used the same word "agapao" consistently', 'Jesus used "eros" and Peter used "agapao"', 'a', 'In the Greek text, Jesus asks with "agapas me" twice, then "phileis me" the third time. Peter answers "philo se" all three times.'),
('John', 21, 'adults', 5, 'What did Peter ask Jesus about the beloved disciple?', '"Lord, and what shall this man do?" — Jesus replied "If I will that he tarry till I come, what is that to thee? follow thou me"', '"Will he also suffer for your name?"', '"Is he greater than I in your sight?"', '"Shall he lead the church after you go?"', 'a', 'John 21:21-22 — "Lord, and what shall this man do? Jesus saith unto him, If I will that he tarry till I come, what is that to thee? follow thou me."'),
('John', 21, 'adults', 6, 'What rumor spread among the brethren based on Jesus'' words about the beloved disciple?', 'That the beloved disciple would not die — but John clarifies Jesus did not say that', 'That the beloved disciple would become the next high priest', 'That the beloved disciple would write a Gospel', 'That the beloved disciple would travel to Rome', 'a', 'John 21:23 — "Then went this saying abroad among the brethren, that that disciple should not die: yet Jesus said not unto him, He shall not die."'),
('John', 21, 'adults', 7, 'How does the final verse of John''s Gospel describe the extent of Jesus'' works?', '"If they should be written every one… even the world itself could not contain the books that should be written"', '"His works were so numerous that no man could count them"', '"The scrolls of the temple could not hold all His deeds"', '"A thousand scribes writing day and night could not finish"', 'a', 'John 21:25 — "if they should be written every one, I suppose that even the world itself could not contain the books that should be written."'),
('John', 21, 'adults', 8, 'How many times total had Jesus appeared to the disciples after the resurrection, according to John''s count at the Sea of Tiberias?', 'This was the third time Jesus showed Himself to the disciples after He was risen', 'This was the second appearance to the disciples', 'This was the fourth time Jesus appeared', 'This was the fifth appearance recorded by John', 'a', 'John 21:14 — "This is now the third time that Jesus shewed himself to his disciples, after that he was risen from the dead."');
